package com.opengamma.strata.measure.fxopt;

import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
import com.opengamma.strata.data.scenario.CurrencyScenarioArray;
import com.opengamma.strata.data.scenario.MultiCurrencyScenarioArray;
import com.opengamma.strata.data.scenario.ScenarioArray;
import com.opengamma.strata.data.scenario.ScenarioMarketData;
import com.opengamma.strata.market.param.CurrencyParameterSensitivities;
import com.opengamma.strata.measure.rate.RatesMarketDataLookup;
import com.opengamma.strata.pricer.fxopt.BlackFxEuropeanOptionTradePricer;
import com.opengamma.strata.pricer.fxopt.FxOptionVolatilities;
import com.opengamma.strata.pricer.fxopt.VannaVolgaFxEuropeanOptionTradePricer;
import com.opengamma.strata.pricer.rate.RatesProvider;
import com.opengamma.strata.product.fxopt.FxEuropeanOptionTrade;
import com.opengamma.strata.product.fxopt.ResolvedFxEuropeanOptionTrade;

/**
 * Calculates pricing and risk measures for FX European option trades.
 * <p>
 * This provides a high-level entry point for FX European option pricing and risk measures.
 * Pricing is performed using the Black method.
 * <p>
 * Each method takes a {@link ResolvedFxEuropeanOptionTrade}, whereas application code will
 * typically work with {@link FxEuropeanOptionTrade}. Call
 * {@link FxEuropeanOptionTrade#resolve(com.opengamma.strata.basics.ReferenceData) FxEuropeanOptionTrade::resolve(ReferenceData)}
 * to convert {@code FxEuropeanOptionTrade} to {@code ResolvedFxEuropeanOptionTrade}.
 */
public class FxEuropeanOptionTradeCalculations {

  /**
   * Default implementation.
   */
  public static final FxEuropeanOptionTradeCalculations DEFAULT = new FxEuropeanOptionTradeCalculations(
      BlackFxEuropeanOptionTradePricer.DEFAULT,
      VannaVolgaFxEuropeanOptionTradePricer.DEFAULT);

  /**
   * Pricer for {@link ResolvedFxEuropeanOptionTrade}.
   */
  private final FxEuropeanOptionMeasureCalculations calc;

  /**
   * Creates an instance.
   * <p>
   * In most cases, applications should use the {@link #DEFAULT} instance.
   *
   * @param blackPricer  the pricer for {@link ResolvedFxEuropeanOptionTrade} using Black
   * @param vannaVolgaPricer  the pricer for {@link ResolvedFxEuropeanOptionTrade} using Vanna-Volga
   */
  public FxEuropeanOptionTradeCalculations(
      BlackFxEuropeanOptionTradePricer blackPricer,
      VannaVolgaFxEuropeanOptionTradePricer vannaVolgaPricer) {
    this.calc = new FxEuropeanOptionMeasureCalculations(blackPricer, vannaVolgaPricer);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates present value across one or more scenarios.
   *
   * @param trade  the trade
   * @param ratesLookup  the lookup used to query the market data
   * @param fxLookup  the lookup used to query the option market data
   * @param marketData  the market data
   * @param method  the pricing method
   * @return the present value, one entry per scenario
   */
  public MultiCurrencyScenarioArray presentValue(
      ResolvedFxEuropeanOptionTrade trade,
      RatesMarketDataLookup ratesLookup,
      FxOptionMarketDataLookup fxLookup,
      ScenarioMarketData marketData,
      FxEuropeanOptionMethod method) {

    return calc.presentValue(
        trade,
        ratesLookup.marketDataView(marketData),
        fxLookup.marketDataView(marketData),
        method);
  }

  /**
   * Calculates present value for a single set of market data.
   *
   * @param trade  the trade
   * @param ratesProvider  the market data
   * @param volatilities  the option volatilities
   * @param method  the pricing method
   * @return the present value
   */
  public MultiCurrencyAmount presentValue(
      ResolvedFxEuropeanOptionTrade trade,
      RatesProvider ratesProvider,
      FxOptionVolatilities volatilities,
      FxEuropeanOptionMethod method) {

    return calc.presentValue(trade, ratesProvider, volatilities, method);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates present value sensitivity across one or more scenarios.
   * <p>
   * This is the sensitivity of present value to a one basis point shift in the calibrated curves.
   * The result is the sum of the sensitivities of all affected curves.
   *
   * @param trade  the trade
   * @param ratesLookup  the lookup used to query the market data
   * @param fxLookup  the lookup used to query the option market data
   * @param marketData  the market data
   * @param method  the pricing method
