85:   @Override
86:   public PortfolioItemSummary summarize() {
87:     // Long Pay USD 1mm @ GBP/USD 1.32 Premium USD 100k : 21Jan18
88:     StringBuilder buf = new StringBuilder(96);
89:     CurrencyAmount base = product.getUnderlying().getBaseCurrencyAmount();
90:     CurrencyAmount counter = product.getUnderlying().getCounterCurrencyAmount();
91:     buf.append(product.getLongShort());
92:     buf.append(' ');
93:     buf.append(SummarizerUtils.fx(base, counter));
94:     buf.append(" Premium ");
95:     buf.append(SummarizerUtils.amount(premium.getValue().mapAmount(v -> Math.abs(v))));
96:     buf.append(" : ");
97:     buf.append(SummarizerUtils.date(product.getExpiryDate()));
98:     CurrencyPair currencyPair = product.getCurrencyPair();
99:     return SummarizerUtils.summary(
100:         this, ProductType.FX_VANILLA_OPTION, buf.toString(), currencyPair.getBase(), currencyPair.getCounter());
101:   }
