35: /**
36:  * FX (European) single barrier option.
37:  * <p>
38:  * An FX option is a financial instrument that provides an option to exchange two currencies at a specified future time
39:  * only when barrier event occurs (knock-in option) or does not occur (knock-out option).
40:  * <p>
41:  * Depending on the barrier defined in {@link Barrier}, the options are classified into four types: up-and-in,
42:  * down-and-in, up-and-out and down-and-out.
43:  * <p>
44:  * For example, an up-and-out call on a 'EUR 1.00 / USD -1.41' exchange with barrier of 1.5 is the option to
45:  * perform a foreign exchange on the expiry date, where USD 1.41 is paid to receive EUR 1.00, only when EUR/USD rate does
46:  * not exceed 1.5 during the barrier event observation period.
47:  * <p>
48:  * In case of the occurrence (non-occurrence for knock-in options) of the barrier event, the option becomes worthless,
49:  * or alternatively, a rebate is made.
50:  */
51: @BeanDefinition
52: public final class FxSingleBarrierOption
53:     implements FxOptionProduct, Resolvable<ResolvedFxSingleBarrierOption>, ImmutableBean, Serializable {
54: 
55:   /**
56:    * The underlying FX vanilla option.
57:    */
58:   @PropertyDefinition(validate = "notNull")
59:   private final FxVanillaOption underlyingOption;
60:   /**
61:    * The barrier description.
62:    * <p>
63:    * The barrier level stored in this field must be represented based on the direction of the currency pair in the
64:    * underlying FX transaction.
65:    * <p>
66:    * For example, if the underlying option is an option on EUR/GBP, the barrier should be a certain level of EUR/GBP rate.
67:    */
68:   @PropertyDefinition(validate = "notNull")
69:   private final Barrier barrier;
70:   /**
71:    * For a 'out' option, the amount is paid when the barrier is reached;
72:    * for a 'in' option, the amount is paid at expiry if the barrier is not reached.
73:    * <p>
74:    * This is the notional amount represented in one of the currency pair.
75:    * The amount should be positive.
76:    */
77:   @PropertyDefinition(get = "optional")
78:   private final CurrencyAmount rebate;
79: 
80:   //-------------------------------------------------------------------------
81:   /**
82:    * Obtains FX single barrier option with rebate.
83:    *
84:    * @param underlyingOption  the underlying FX vanilla option
85:    * @param barrier  the barrier
86:    * @param rebate  the rebate
87:    * @return the instance
88:    */
89:   public static FxSingleBarrierOption of(FxVanillaOption underlyingOption, Barrier barrier, CurrencyAmount rebate) {
90:     return new FxSingleBarrierOption(underlyingOption, barrier, rebate);
91:   }
92: 
93:   /**
94:    * Obtains FX single barrier option without rebate.
95:    *
96:    * @param underlyingOption  the underlying FX vanilla option
97:    * @param barrier  the barrier
98:    * @return the instance
99:    */
100:   public static FxSingleBarrierOption of(FxVanillaOption underlyingOption, Barrier barrier) {
101:     return new FxSingleBarrierOption(underlyingOption, barrier, null);
102:   }
103: 
104:   //-------------------------------------------------------------------------
105:   @ImmutableValidator
106:   private void validate() {
107:     if (rebate != null) {
108:       ArgChecker.isTrue(rebate.getAmount() > 0d, "rebate must be positive");
109:       ArgChecker.isTrue(underlyingOption.getUnderlying().getCurrencyPair().contains(rebate.getCurrency()),
110:           "The rebate currency must be one of underlying currency pair");
111:     }
112:   }
113: 
114:   //-------------------------------------------------------------------------
115:   /**
116:    * Gets currency pair of the base currency and counter currency.
117:    * <p>
118:    * This currency pair is conventional, thus indifferent to the direction of FX.
119:    *
120:    * @return the currency pair
121:    */
122:   @Override
123:   public CurrencyPair getCurrencyPair() {
124:     return underlyingOption.getCurrencyPair();
125:   }
126: 
127:   //-----------------------------------------------------------------------
128:   /**
129:    * Gets the underlying Fx vanilla option's expiry.
130:    * @return the expiry
131:    */
132:   @Override
133:   public ZonedDateTime getExpiry() {
134:     return underlyingOption.getExpiry();
135:   }
136: 
137:   //-------------------------------------------------------------------------
138:   @Override
139:   public ResolvedFxSingleBarrierOption resolve(ReferenceData refData) {
140:     if (rebate != null) {
141:       return ResolvedFxSingleBarrierOption.of(underlyingOption.resolve(refData), barrier, rebate);
142:     }
143:     return ResolvedFxSingleBarrierOption.of(underlyingOption.resolve(refData), barrier);
144:   }
