7: 
8: import com.opengamma.strata.basics.currency.CurrencyAmount;
9: import com.opengamma.strata.basics.currency.CurrencyPair;
10: import com.opengamma.strata.basics.currency.FxRate;
11: import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
12: import com.opengamma.strata.basics.value.ValueDerivatives;
13: import com.opengamma.strata.collect.ArgChecker;
14: import com.opengamma.strata.market.sensitivity.PointSensitivities;
15: import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
16: import com.opengamma.strata.pricer.fx.DiscountingFxSingleProductPricer;
17: import com.opengamma.strata.pricer.impl.option.BlackFormulaRepository;
18: import com.opengamma.strata.pricer.rate.RatesProvider;
19: import com.opengamma.strata.product.fx.ResolvedFxSingle;
20: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOption;
21: 
22: /**
23:  * Pricer for foreign exchange vanilla option transaction products with a lognormal model.
24:  * <p>
25:  * This function provides the ability to price an {@link ResolvedFxVanillaOption}.
26:  * <p>
27:  * All of the computation is be based on the counter currency of the underlying FX transaction.
28:  * For example, price, PV and risk measures of the product will be expressed in USD for an option on EUR/USD.
29:  */
30: public class BlackFxVanillaOptionProductPricer {
31: 
32:   /**
33:    * Default implementation.
34:    */
35:   public static final BlackFxVanillaOptionProductPricer DEFAULT =
36:       new BlackFxVanillaOptionProductPricer(DiscountingFxSingleProductPricer.DEFAULT);
37: 
38:   /**
39:    * Underlying FX pricer.
40:    */
41:   private final DiscountingFxSingleProductPricer fxPricer;
42: 
43:   /**
44:    * Creates an instance.
45:    * 
46:    * @param fxPricer  the pricer for {@link ResolvedFxSingle}
47:    */
48:   public BlackFxVanillaOptionProductPricer(
49:       DiscountingFxSingleProductPricer fxPricer) {
50:     this.fxPricer = ArgChecker.notNull(fxPricer, "fxPricer");
51:   }
52: 
53:   //-------------------------------------------------------------------------
54:   /**
55:    * Returns the pricer used to price the underlying FX product.
56:    * 
57:    * @return the pricer
58:    */
59:   DiscountingFxSingleProductPricer getDiscountingFxSingleProductPricer() {
60:     return fxPricer;
61:   }
62: 
63:   //-------------------------------------------------------------------------
64:   /**
65:    * Calculates the price of the foreign exchange vanilla option product.
66:    * <p>
67:    * The price of the product is the value on the valuation date for one unit of the base currency 
68:    * and is expressed in the counter currency. The price does not take into account the long/short flag.
69:    * See {@link #presentValue} for scaling and currency.
70:    * 
71:    * @param option  the option product
72:    * @param ratesProvider  the rates provider
73:    * @param volatilities  the Black volatility provider
74:    * @return the price of the product
75:    */
76:   public double price(
77:       ResolvedFxVanillaOption option,
78:       RatesProvider ratesProvider,
79:       BlackFxOptionVolatilities volatilities) {
80: 
81:     ResolvedFxSingle underlying = option.getUnderlying();
82:     double forwardPrice = undiscountedPrice(option, ratesProvider, volatilities);
83:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
84:     return discountFactor * forwardPrice;
85:   }
86: 
87:   /**
88:    * Calculates the present value of the foreign exchange vanilla option product.
89:    * <p>
90:    * The present value of the product is the value on the valuation date.
91:    * It is expressed in the counter currency.
92:    * 
93:    * @param option  the option product
94:    * @param ratesProvider  the rates provider
95:    * @param volatilities  the Black volatility provider
96:    * @return the present value of the product
97:    */
98:   public CurrencyAmount presentValue(
99:       ResolvedFxVanillaOption option,
100:       RatesProvider ratesProvider,
101:       BlackFxOptionVolatilities volatilities) {
102: 
103:     double price = price(option, ratesProvider, volatilities);
104:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * price);
105:   }
106: 
107:   // the price without discounting
108:   private double undiscountedPrice(
109:       ResolvedFxVanillaOption option,
110:       RatesProvider ratesProvider,
111:       BlackFxOptionVolatilities volatilities) {
112: 
113:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
114:     if (timeToExpiry < 0d) {
115:       return 0d;
116:     }
117:     ResolvedFxSingle underlying = option.getUnderlying();
118:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
119:     CurrencyPair strikePair = underlying.getCurrencyPair();
120:     double forwardRate = forward.fxRate(strikePair);
121:     double strikeRate = option.getStrike();
122:     boolean isCall = option.getPutCall().isCall();
123:     if (timeToExpiry == 0d) {
124:       return isCall ? Math.max(forwardRate - strikeRate, 0d) : Math.max(0d, strikeRate - forwardRate);
125:     }
126:     double volatility = volatilities.volatility(strikePair, option.getExpiry(), strikeRate, forwardRate);
127:     return BlackFormulaRepository.price(forwardRate, strikeRate, timeToExpiry, volatility, isCall);
128:   }
129: 
130:   //-------------------------------------------------------------------------
131:   /**
132:    * Calculates the delta of the foreign exchange vanilla option product.
133:    * <p>
134:    * The delta is the first derivative of {@link #price} with respect to spot.
135:    * 
136:    * @param option  the option product
137:    * @param ratesProvider  the rates provider
138:    * @param volatilities  the Black volatility provider
139:    * @return the delta of the product
140:    */
141:   public double delta(
142:       ResolvedFxVanillaOption option,
143:       RatesProvider ratesProvider,
144:       BlackFxOptionVolatilities volatilities) {
145: 
146:     ResolvedFxSingle underlying = option.getUnderlying();
147:     double fwdDelta = undiscountedDelta(option, ratesProvider, volatilities);
148:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
149:     double fwdRateSpotSensitivity = fxPricer.forwardFxRateSpotSensitivity(
150:         option.getPutCall().isCall() ? underlying : underlying.inverse(), ratesProvider);
151:     return fwdDelta * discountFactor * fwdRateSpotSensitivity;
152:   }
153: 
154:   /**
155:    * Calculates the present value delta of the foreign exchange vanilla option product.
156:    * <p>
157:    * The present value delta is the first derivative of {@link #presentValue} with respect to spot.
158:    * 
159:    * @param option  the option product
160:    * @param ratesProvider  the rates provider
161:    * @param volatilities  the Black volatility provider
162:    * @return the present value delta of the product
163:    */
164:   public CurrencyAmount presentValueDelta(
165:       ResolvedFxVanillaOption option,
166:       RatesProvider ratesProvider,
167:       BlackFxOptionVolatilities volatilities) {
168: 
169:     double delta = delta(option, ratesProvider, volatilities);
170:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * delta);
171:   }
172: 
173:   /**
174:    * Calculates the present value sensitivity of the foreign exchange vanilla option product.
175:    * <p>
176:    * The present value sensitivity of the product is the sensitivity of {@link #presentValue} to
177:    * the underlying curves.
178:    * <p>
179:    * The volatility is fixed in this sensitivity computation.
180:    * 
181:    * @param option  the option product
182:    * @param ratesProvider  the rates provider
183:    * @param volatilities  the Black volatility provider
184:    * @return the present value curve sensitivity of the product
185:    */
186:   public PointSensitivities presentValueSensitivityRatesStickyStrike(
187:       ResolvedFxVanillaOption option,
188:       RatesProvider ratesProvider,
189:       BlackFxOptionVolatilities volatilities) {
190: 
191:     if (volatilities.relativeTime(option.getExpiry()) < 0d) {
192:       return PointSensitivities.empty();
193:     }
194:     ResolvedFxSingle underlying = option.getUnderlying();
195:     double fwdDelta = undiscountedDelta(option, ratesProvider, volatilities);
196:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
197:     double notional = signedNotional(option);
198:     PointSensitivityBuilder fwdSensi = fxPricer.forwardFxRatePointSensitivity(
199:         option.getPutCall().isCall() ? underlying : underlying.inverse(), ratesProvider)
200:         .multipliedBy(notional * discountFactor * fwdDelta);
201:     double fwdPrice = undiscountedPrice(option, ratesProvider, volatilities);
202:     PointSensitivityBuilder dscSensi = ratesProvider.discountFactors(option.getCounterCurrency())
203:         .zeroRatePointSensitivity(underlying.getPaymentDate()).multipliedBy(notional * fwdPrice);
204:     return fwdSensi.combinedWith(dscSensi).build().convertedTo(option.getCounterCurrency(), ratesProvider);
205:   }
206: 
207:   // the delta without discounting
208:   private double undiscountedDelta(
209:       ResolvedFxVanillaOption option,
210:       RatesProvider ratesProvider,
211:       BlackFxOptionVolatilities volatilities) {
212: 
213:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
214:     if (timeToExpiry < 0d) {
215:       return 0d;
216:     }
217:     ResolvedFxSingle underlying = option.getUnderlying();
218:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
219:     CurrencyPair strikePair = underlying.getCurrencyPair();
220:     double forwardRate = forward.fxRate(strikePair);
221:     double strikeRate = option.getStrike();
222:     boolean isCall = option.getPutCall().isCall();
223:     if (timeToExpiry == 0d) {
224:       return isCall ? (forwardRate > strikeRate ? 1d : 0d) : (strikeRate > forwardRate ? -1d : 0d);
225:     }
226:     double volatility = volatilities.volatility(strikePair, option.getExpiry(), strikeRate, forwardRate);
227:     return BlackFormulaRepository.delta(forwardRate, strikeRate, timeToExpiry, volatility, isCall);
228:   }
229: 
230:   //-------------------------------------------------------------------------
231:   /**
232:    * Calculates the smile adjusted delta of the foreign exchange vanilla option product.
233:    * <p>
234:    * The delta is the first derivative of {@link #price} with respect to spot.
235:    * The sensitivity of the volatility to spot is also included in this method,
236:    * that is based on how FX option volatility surface is constructed in {@code BlackFxOptionVolatilities}.
237:    *
238:    * @param option  the option product
239:    * @param ratesProvider  the rates provider
240:    * @param volatilities  the Black volatility provider
241:    * @return the delta of the product
242:    */
243:   public double smileAdjustedDelta(
244:       ResolvedFxVanillaOption option,
245:       RatesProvider ratesProvider,
246:       BlackFxOptionVolatilities volatilities) {
247: 
248:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
249:     if (timeToExpiry < 0d) {
250:       return 0d;
251:     }
252:     ResolvedFxSingle underlying = option.getUnderlying();
253:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
254:     CurrencyPair strikePair = underlying.getCurrencyPair();
255:     double forwardRate = forward.fxRate(strikePair);
256:     double strikeRate = option.getStrike();
257:     boolean isCall = option.getPutCall().isCall();
258:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
259:     double fwdRateSpotSensitivity = fxPricer.forwardFxRateSpotSensitivity(
260:         isCall ? underlying : underlying.inverse(),
261:         ratesProvider);
262:     if (timeToExpiry == 0d) {
263:       double forwardDelta = isCall ? (forwardRate > strikeRate ? 1d : 0d) : (strikeRate > forwardRate ? -1d : 0d);
264:       return discountFactor * forwardDelta * fwdRateSpotSensitivity;
265:     }
266:     ValueDerivatives volatilityDerivatives = volatilities.firstPartialDerivatives(
267:         strikePair,
268:         timeToExpiry,
269:         strikeRate,
270:         forwardRate);
271:     double fwdVega = BlackFormulaRepository.vega(
272:         forwardRate,
273:         strikeRate,
274:         timeToExpiry,
275:         volatilityDerivatives.getValue());
276:     double fwdDelta = BlackFormulaRepository.delta(
277:         forwardRate,
278:         strikeRate,
279:         timeToExpiry,
280:         volatilityDerivatives.getValue(),
281:         isCall);
282:     return (fwdDelta + fwdVega * volatilityDerivatives.getDerivative(2)) * discountFactor * fwdRateSpotSensitivity;
283:   }
284: 
285:   //-------------------------------------------------------------------------
286:   /**
287:    * Calculates the gamma of the foreign exchange vanilla option product.
288:    * <p>
289:    * The gamma is the second derivative of {@link #price} with respect to spot.
290:    * 
291:    * @param option  the option product
292:    * @param ratesProvider  the rates provider
293:    * @param volatilities  the Black volatility provider
294:    * @return the gamma of the product
295:    */
296:   public double gamma(
297:       ResolvedFxVanillaOption option,
298:       RatesProvider ratesProvider,
299:       BlackFxOptionVolatilities volatilities) {
300: 
301:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
302:     if (timeToExpiry <= 0d) {
303:       return 0d;
304:     }
305:     ResolvedFxSingle underlying = option.getUnderlying();
306:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
307:     CurrencyPair strikePair = underlying.getCurrencyPair();
308:     double forwardRate = forward.fxRate(strikePair);
309:     double strikeRate = option.getStrike();
310:     double volatility = volatilities.volatility(
311:         strikePair, option.getExpiry(), strikeRate, forwardRate);
312:     double forwardGamma = BlackFormulaRepository.gamma(forwardRate, strikeRate, timeToExpiry, volatility);
313:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
314:     double fwdRateSpotSensitivity = fxPricer.forwardFxRateSpotSensitivity(
315:         option.getPutCall().isCall() ? underlying : underlying.inverse(), ratesProvider);
316:     return forwardGamma * discountFactor * fwdRateSpotSensitivity * fwdRateSpotSensitivity;
317:   }
318: 
319:   /**
320:    * Calculates the present value delta of the foreign exchange vanilla option product.
321:    * <p>
322:    * The present value gamma is the second derivative of the {@link #presentValue} with respect to spot.
323:    * 
324:    * @param option  the option product
325:    * @param ratesProvider  the rates provider
326:    * @param volatilities  the Black volatility provider
327:    * @return the present value gamma of the product
328:    */
329:   public CurrencyAmount presentValueGamma(
330:       ResolvedFxVanillaOption option,
331:       RatesProvider ratesProvider,
332:       BlackFxOptionVolatilities volatilities) {
333: 
334:     double gamma = gamma(option, ratesProvider, volatilities);
335:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * gamma);
336:   }
337: 
338:   //-------------------------------------------------------------------------
339:   /**
340:    * Calculates the vega of the foreign exchange vanilla option product.
341:    * <p>
342:    * The vega is the first derivative of {@link #price} with respect to volatility.
343:    * 
344:    * @param option  the option product
345:    * @param ratesProvider  the rates provider
346:    * @param volatilities  the Black volatility provider
347:    * @return the vega of the product
348:    */
349:   public double vega(
350:       ResolvedFxVanillaOption option,
351:       RatesProvider ratesProvider,
352:       BlackFxOptionVolatilities volatilities) {
353: 
354:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
355:     if (timeToExpiry <= 0d) {
356:       return 0d;
357:     }
358:     ResolvedFxSingle underlying = option.getUnderlying();
359:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
360:     CurrencyPair strikePair = underlying.getCurrencyPair();
361:     double forwardRate = forward.fxRate(strikePair);
362:     double strikeRate = option.getStrike();
363:     double volatility = volatilities.volatility(strikePair, option.getExpiry(), strikeRate, forwardRate);
364:     double fwdVega = BlackFormulaRepository.vega(forwardRate, strikeRate, timeToExpiry, volatility);
365:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
366:     return discountFactor * fwdVega;
367:   }
368: 
369:   /**
370:    * Calculates the present value vega of the foreign exchange vanilla option product.
371:    * <p>
372:    * The present value vega is the first derivative of the {@link #presentValue} with respect to volatility.
373:    * 
374:    * @param option  the option product
375:    * @param ratesProvider  the rates provider
376:    * @param volatilities  the Black volatility provider
377:    * @return the present value vega of the product
378:    */
379:   public CurrencyAmount presentValueVega(
380:       ResolvedFxVanillaOption option,
381:       RatesProvider ratesProvider,
382:       BlackFxOptionVolatilities volatilities) {
383: 
384:     double vega = vega(option, ratesProvider, volatilities);
385:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * vega);
386:   }
387: 
388:   /**
389:    * Computes the present value sensitivity to the black volatility used in the pricing.
390:    * <p>
391:    * The result is a single sensitivity to the volatility used.
392:    * 
393:    * @param option  the option product
394:    * @param ratesProvider  the rates provider
395:    * @param volatilities  the Black volatility provider
396:    * @return the present value sensitivity
397:    */
398:   public PointSensitivityBuilder presentValueSensitivityModelParamsVolatility(
399:       ResolvedFxVanillaOption option,
400:       RatesProvider ratesProvider,
401:       BlackFxOptionVolatilities volatilities) {
402: 
403:     if (volatilities.relativeTime(option.getExpiry()) <= 0d) {
404:       return PointSensitivityBuilder.none();
405:     }
406:     ResolvedFxSingle underlying = option.getUnderlying();
407:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
408:     CurrencyPair strikePair = underlying.getCurrencyPair();
409:     CurrencyAmount valueVega = presentValueVega(option, ratesProvider, volatilities);
410:     return FxOptionSensitivity.of(
411:         volatilities.getName(),
412:         strikePair,
413:         volatilities.relativeTime(option.getExpiry()),
414:         option.getStrike(),
415:         forward.fxRate(strikePair),
416:         valueVega.getCurrency(),
417:         valueVega.getAmount());
418:   }
419: 
420:   //-------------------------------------------------------------------------
421:   /**
422:    * Calculates the Black theta of the foreign exchange vanilla option product.
423:    * <p>
424:    * The theta is the negative of the first derivative of {@link #price} with respect to time parameter
425:    * in Black formula (the discounted driftless theta).
426:    * 
427:    * @param option  the option product
428:    * @param ratesProvider  the rates provider
429:    * @param volatilities  the Black volatility provider
430:    * @return the theta of the product
431:    */
432:   public double theta(
433:       ResolvedFxVanillaOption option,
434:       RatesProvider ratesProvider,
435:       BlackFxOptionVolatilities volatilities) {
436: 
437:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
438:     if (timeToExpiry <= 0d) {
439:       return 0d;
440:     }
441:     ResolvedFxSingle underlying = option.getUnderlying();
442:     FxRate forward = fxPricer.forwardFxRate(underlying, ratesProvider);
443:     CurrencyPair strikePair = underlying.getCurrencyPair();
444:     double forwardRate = forward.fxRate(strikePair);
445:     double strikeRate = option.getStrike();
446:     double volatility = volatilities.volatility(
447:         strikePair, option.getExpiry(), strikeRate, forwardRate);
448:     double fwdTheta = BlackFormulaRepository.driftlessTheta(forwardRate, strikeRate, timeToExpiry, volatility);
449:     double discountFactor = ratesProvider.discountFactor(option.getCounterCurrency(), underlying.getPaymentDate());
450:     return discountFactor * fwdTheta;
451:   }
452: 
453:   /**
454:    * Calculates the present value theta of the foreign exchange vanilla option product.
455:    * <p>
456:    * The present value theta is the negative of the first derivative of {@link #presentValue} with time parameter
457:    * in Black formula, i.e., the driftless theta of the present value.
458:    * 
459:    * @param option  the option product
460:    * @param ratesProvider  the rates provider
461:    * @param volatilities  the Black volatility provider
462:    * @return the present value vega of the product
463:    */
464:   public CurrencyAmount presentValueTheta(
465:       ResolvedFxVanillaOption option,
466:       RatesProvider ratesProvider,
467:       BlackFxOptionVolatilities volatilities) {
468: 
469:     double theta = theta(option, ratesProvider, volatilities);
470:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * theta);
471:   }
472: 
473:   //-------------------------------------------------------------------------
474:   /**
475:    * Calculates the forward exchange rate.
476:    *
477:    * @param option  the option product
478:    * @param ratesProvider  the rates provider
479:    * @return the forward rate
480:    */
481:   public FxRate forwardFxRate(ResolvedFxVanillaOption option, RatesProvider ratesProvider) {
482:     return fxPricer.forwardFxRate(option.getUnderlying(), ratesProvider);
483:   }
484: 
485:   //-------------------------------------------------------------------------
486:   /**
487:    * Calculates the implied Black volatility of the foreign exchange vanilla option product.
488:    * 
489:    * @param option  the option product
490:    * @param ratesProvider  the rates provider
491:    * @param volatilities  the Black volatility provider
492:    * @return the implied volatility of the product
493:    * @throws IllegalArgumentException if the option has expired
494:    */
495:   public double impliedVolatility(
496:       ResolvedFxVanillaOption option,
497:       RatesProvider ratesProvider,
498:       BlackFxOptionVolatilities volatilities) {
499: 
500:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
501:     if (timeToExpiry <= 0d) {
502:       throw new IllegalArgumentException("valuation is after option's expiry.");
503:     }
504:     FxRate forward = forwardFxRate(option, ratesProvider);
505:     CurrencyPair strikePair = option.getUnderlying().getCurrencyPair();
506:     return volatilities.volatility(
507:         strikePair, option.getExpiry(), option.getStrike(), forward.fxRate(strikePair));
508:   }
509: 
510:   //-------------------------------------------------------------------------
511:   /**
512:    * Calculates the currency exposure of the foreign exchange vanilla option product.
513:    * 
514:    * @param option  the option product
515:    * @param ratesProvider  the rates provider
516:    * @param volatilities  the Black volatility provider
517:    * @return the currency exposure
518:    */
519:   public MultiCurrencyAmount currencyExposure(
520:       ResolvedFxVanillaOption option,
521:       RatesProvider ratesProvider,
522:       BlackFxOptionVolatilities volatilities) {
523: 
524:     double delta = delta(option, ratesProvider, volatilities);
525:     return currencyExposureFromDelta(delta, option, ratesProvider, volatilities);
526:   }
527: 
528:   /**
529:    * Calculates the currency exposure of the foreign exchange vanilla option product, with smile adjustment included.
530:    * <p>
531:    * The smile adjustment is based on {@link BlackFxVanillaOptionProductPricer#smileAdjustedDelta}.
532:    *
533:    * @param option  the option product
534:    * @param ratesProvider  the rates provider
535:    * @param volatilities  the Black volatility provider
536:    * @return the currency exposure
537:    */
538:   public MultiCurrencyAmount smileAdjustedCurrencyExposure(
539:       ResolvedFxVanillaOption option,
540:       RatesProvider ratesProvider,
541:       BlackFxOptionVolatilities volatilities) {
542: 
543:     double delta = smileAdjustedDelta(option, ratesProvider, volatilities);
544:     return currencyExposureFromDelta(delta, option, ratesProvider, volatilities);
545:   }
546: 
547:   private MultiCurrencyAmount currencyExposureFromDelta(
548:       double delta,
549:       ResolvedFxVanillaOption option,
550:       RatesProvider ratesProvider,
551:       BlackFxOptionVolatilities volatilities) {
552: 
553:     CurrencyPair strikePair = option.getUnderlying().getCurrencyPair();
554:     double price = price(option, ratesProvider, volatilities);
555:     double spot = ratesProvider.fxRate(strikePair);
556:     double signedNotional = signedNotional(option);
557:     CurrencyAmount domestic = CurrencyAmount.of(strikePair.getCounter(), (price - delta * spot) * signedNotional);
558:     CurrencyAmount foreign = CurrencyAmount.of(strikePair.getBase(), delta * signedNotional);
559:     return MultiCurrencyAmount.of(domestic, foreign);
560:   }
561: 
562:   //-------------------------------------------------------------------------
563:   // signed notional amount to computed present value and value Greeks
564:   private double signedNotional(ResolvedFxVanillaOption option) {
565:     return (option.getLongShort().isLong() ? 1d : -1d) *
566:         Math.abs(option.getUnderlying().getBaseCurrencyPayment().getAmount());
567:   }
568: 
569: }
