6: package com.opengamma.strata.pricer.fxopt;
7: 
8: import java.time.LocalDate;
9: 
10: import com.opengamma.strata.basics.currency.CurrencyAmount;
11: import com.opengamma.strata.basics.currency.FxRate;
12: import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
13: import com.opengamma.strata.basics.currency.Payment;
14: import com.opengamma.strata.collect.ArgChecker;
15: import com.opengamma.strata.market.sensitivity.PointSensitivities;
16: import com.opengamma.strata.pricer.DiscountingPaymentPricer;
17: import com.opengamma.strata.pricer.rate.RatesProvider;
18: import com.opengamma.strata.product.fxopt.FxVanillaOptionTrade;
19: import com.opengamma.strata.product.fxopt.ResolvedFxSingleBarrierOption;
20: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOption;
21: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOptionTrade;
22: 
23: /**
24:  * Pricer for FX vanilla option trades with a lognormal model.
25:  * <p>
26:  * This function provides the ability to price an {@link FxVanillaOptionTrade}.
27:  */
28: public class BlackFxVanillaOptionTradePricer {
29: 
30:   /**
31:    * Default implementation.
32:    */
33:   public static final BlackFxVanillaOptionTradePricer DEFAULT = new BlackFxVanillaOptionTradePricer(
34:       BlackFxVanillaOptionProductPricer.DEFAULT,
35:       DiscountingPaymentPricer.DEFAULT);
36: 
37:   /**
38:    * Pricer for {@link ResolvedFxSingleBarrierOption}.
39:    */
40:   private final BlackFxVanillaOptionProductPricer productPricer;
41:   /**
42:    * Pricer for {@link Payment}.
43:    */
44:   private final DiscountingPaymentPricer paymentPricer;
45: 
46:   /**
47:    * Creates an instance.
48:    * 
49:    * @param productPricer  the pricer for {@link ResolvedFxVanillaOption}
50:    * @param paymentPricer  the pricer for {@link Payment}
51:    */
52:   public BlackFxVanillaOptionTradePricer(
53:       BlackFxVanillaOptionProductPricer productPricer,
54:       DiscountingPaymentPricer paymentPricer) {
55:     this.productPricer = ArgChecker.notNull(productPricer, "productPricer");
56:     this.paymentPricer = ArgChecker.notNull(paymentPricer, "paymentPricer");
57:   }
58: 
59:   //-------------------------------------------------------------------------
60:   /**
61:    * Calculates the present value of the FX vanilla option trade.
62:    * <p>
63:    * The present value of the trade is the value on the valuation date.
64:    * 
65:    * @param trade  the option trade
66:    * @param ratesProvider  the rates provider
67:    * @param volatilities  the Black volatility provider
68:    * @return the present value of the trade
69:    */
70:   public MultiCurrencyAmount presentValue(
71:       ResolvedFxVanillaOptionTrade trade,
72:       RatesProvider ratesProvider,
73:       BlackFxOptionVolatilities volatilities) {
74: 
75:     ResolvedFxVanillaOption product = trade.getProduct();
76:     CurrencyAmount pvProduct = productPricer.presentValue(product, ratesProvider, volatilities);
77:     Payment premium = trade.getPremium();
78:     CurrencyAmount pvPremium = paymentPricer.presentValue(premium, ratesProvider);
79:     return MultiCurrencyAmount.of(pvProduct).plus(pvPremium);
80:   }
81: 
82:   //-------------------------------------------------------------------------
83:   /**
84:    * Calculates the present value sensitivity of the FX vanilla option trade.
85:    * <p>
86:    * The present value sensitivity of the trade is the sensitivity of the present value to
87:    * the underlying curves.
88:    * <p>
89:    * The volatility is fixed in this sensitivity computation.
90:    * 
91:    * @param trade  the option trade
92:    * @param ratesProvider  the rates provider
93:    * @param volatilities  the Black volatility provider
94:    * @return the present value curve sensitivity of the trade
95:    */
96:   public PointSensitivities presentValueSensitivityRatesStickyStrike(
97:       ResolvedFxVanillaOptionTrade trade,
98:       RatesProvider ratesProvider,
99:       BlackFxOptionVolatilities volatilities) {
100: 
101:     ResolvedFxVanillaOption product = trade.getProduct();
102:     PointSensitivities pvcsProduct =
103:         productPricer.presentValueSensitivityRatesStickyStrike(product, ratesProvider, volatilities);
104:     Payment premium = trade.getPremium();
105:     PointSensitivities pvcsPremium = paymentPricer.presentValueSensitivity(premium, ratesProvider).build();
106:     return pvcsProduct.combinedWith(pvcsPremium);
107:   }
108: 
109:   //-------------------------------------------------------------------------
110:   /**
111:    * Computes the present value sensitivity to the black volatility used in the pricing.
112:    * <p>
113:    * The result is a single sensitivity to the volatility used.
114:    * 
115:    * @param trade  the option trade
116:    * @param ratesProvider  the rates provider
117:    * @param volatilities  the Black volatility provider
118:    * @return the present value sensitivity
119:    */
120:   public PointSensitivities presentValueSensitivityModelParamsVolatility(
121:       ResolvedFxVanillaOptionTrade trade,
122:       RatesProvider ratesProvider,
123:       BlackFxOptionVolatilities volatilities) {
124: 
125:     ResolvedFxVanillaOption product = trade.getProduct();
126:     return productPricer.presentValueSensitivityModelParamsVolatility(product, ratesProvider, volatilities).build();
127:   }
128: 
129:   //-------------------------------------------------------------------------
130:   /**
131:    * Calculates the currency exposure of the FX vanilla option trade.
132:    * 
133:    * @param trade  the option trade
134:    * @param ratesProvider  the rates provider
135:    * @param volatilities  the Black volatility provider
136:    * @return the currency exposure
137:    */
138:   public MultiCurrencyAmount currencyExposure(
139:       ResolvedFxVanillaOptionTrade trade,
140:       RatesProvider ratesProvider,
141:       BlackFxOptionVolatilities volatilities) {
142: 
143:     Payment premium = trade.getPremium();
144:     CurrencyAmount pvPremium = paymentPricer.presentValue(premium, ratesProvider);
145:     ResolvedFxVanillaOption product = trade.getProduct();
146:     return productPricer.currencyExposure(product, ratesProvider, volatilities).plus(pvPremium);
147:   }
148: 
149:   /**
150:    * Calculates the smile adjusted currency exposure of the FX vanilla option trade.
151:    *
152:    * @param trade  the option trade
153:    * @param ratesProvider  the rates provider
154:    * @param volatilities  the Black volatility provider
155:    * @return the currency exposure
156:    */
157:   public MultiCurrencyAmount smileAdjustedCurrencyExposure(
158:       ResolvedFxVanillaOptionTrade trade,
159:       RatesProvider ratesProvider,
160:       BlackFxOptionVolatilities volatilities) {
161: 
162:     Payment premium = trade.getPremium();
163:     CurrencyAmount pvPremium = paymentPricer.presentValue(premium, ratesProvider);
164:     ResolvedFxVanillaOption product = trade.getProduct();
165:     return productPricer.smileAdjustedCurrencyExposure(product, ratesProvider, volatilities).plus(pvPremium);
166:   }
167: 
168:   //-------------------------------------------------------------------------
169:   /**
170:    * Calculates the delta of the FX vanilla option trade.
171:    *
172:    * @param trade  the option trade
173:    * @param ratesProvider  the rates provider
174:    * @param volatilities  the Black volatility provider
175:    * @return the delta
176:    */
177:   public double delta(
178:       ResolvedFxVanillaOptionTrade trade,
179:       RatesProvider ratesProvider,
180:       BlackFxOptionVolatilities volatilities) {
181: 
182:     ResolvedFxVanillaOption product = trade.getProduct();
183:     return productPricer.delta(product, ratesProvider, volatilities);
184:   }
185: 
186:   //-------------------------------------------------------------------------
187:   /**
188:    * Calculates the current of the FX vanilla option trade.
189:    * 
190:    * @param trade  the option trade
191:    * @param valuationDate  the valuation date
192:    * @return the current cash amount
193:    */
194:   public CurrencyAmount currentCash(ResolvedFxVanillaOptionTrade trade, LocalDate valuationDate) {
195:     Payment premium = trade.getPremium();
196:     if (premium.getDate().equals(valuationDate)) {
197:       return CurrencyAmount.of(premium.getCurrency(), premium.getAmount());
198:     }
199:     return CurrencyAmount.of(premium.getCurrency(), 0d);
200:   }
201: 
202:   //-------------------------------------------------------------------------
203:   /**
204:    * Calculates the forward exchange rate.
205:    *
206:    * @param trade  the option trade
207:    * @param ratesProvider  the rates provider
208:    * @return the forward rate
209:    */
210:   public FxRate forwardFxRate(ResolvedFxVanillaOptionTrade trade, RatesProvider ratesProvider) {
211:     ResolvedFxVanillaOption product = trade.getProduct();
212:     return productPricer.forwardFxRate(product, ratesProvider);
213:   }
214: 
215:   //-------------------------------------------------------------------------
216:   /**
217:    * Calculates the implied Black volatility of the foreign exchange vanilla option trade.
218:    *
219:    * @param trade  the option trade
220:    * @param ratesProvider  the rates provider
221:    * @param volatilities  the Black volatility provider
222:    * @return the implied volatility of the product
223:    * @throws IllegalArgumentException if the option has expired
224:    */
225:   public double impliedVolatility(
226:       ResolvedFxVanillaOptionTrade trade,
227:       RatesProvider ratesProvider,
228:       BlackFxOptionVolatilities volatilities) {
229: 
230:     ResolvedFxVanillaOption option = trade.getProduct();
231:     return productPricer.impliedVolatility(option, ratesProvider, volatilities);
232:   }
233: 
234: }
