8: import com.opengamma.strata.basics.currency.Currency;
9: import com.opengamma.strata.basics.currency.CurrencyAmount;
10: import com.opengamma.strata.basics.currency.CurrencyPair;
11: import com.opengamma.strata.basics.currency.FxRate;
