13: import com.opengamma.strata.collect.ArgChecker;
14: import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
15: import com.opengamma.strata.pricer.fx.DiscountingFxSingleProductPricer;
16: import com.opengamma.strata.pricer.impl.option.BlackFormulaRepository;
17: import com.opengamma.strata.pricer.rate.RatesProvider;
18: import com.opengamma.strata.product.fx.ResolvedFxSingle;
19: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOption;
