21: /**
22:  * Pricing method for vanilla Forex option transactions with Vanna-Volga method.
23:  * <p>
24:  * The volatilities are expressed using {@code BlackFxOptionSmileVolatilities}. 
25:  * Each smile of the term structure consists of 3 data points, where the middle point corresponds to ATM volatility.
26:  * <p>
27:  * Reference: The vanna-volga method for implied volatilities (2007), A. Castagna and F. Mercurio, Risk, 106-111, January 2007.
28:  * OG implementation: Vanna-volga method for Forex options, version 1.0, June 2012.
29:  */
30: public class VannaVolgaFxVanillaOptionProductPricer {
31: 
32:   /**
33:    * Default implementation.
34:    */
35:   public static final VannaVolgaFxVanillaOptionProductPricer DEFAULT = new VannaVolgaFxVanillaOptionProductPricer(
36:       DiscountingFxSingleProductPricer.DEFAULT);
37: 
38:   /**
39:    * Underlying FX pricer.
40:    */
41:   private final DiscountingFxSingleProductPricer fxPricer;
42: 
43:   /**
44:    * Creates an instance.
45:    * 
46:    * @param fxPricer  the pricer for {@link ResolvedFxSingle}
47:    */
48:   public VannaVolgaFxVanillaOptionProductPricer(DiscountingFxSingleProductPricer fxPricer) {
49:     this.fxPricer = ArgChecker.notNull(fxPricer, "fxPricer");
50:   }
51: 
52:   //-------------------------------------------------------------------------
53:   /**
54:    * Calculates the price of the foreign exchange vanilla option product.
55:    * <p>
56:    * The price of the product is the value on the valuation date for one unit of the base currency 
57:    * and is expressed in the counter currency. The price does not take into account the long/short flag.
58:    * See {@link #presentValue} for scaling and currency.
59:    * 
60:    * @param option  the option product
61:    * @param ratesProvider  the rates provider
62:    * @param volatilities  the Black volatility provider
63:    * @return the price of the product
64:    */
65:   public double price(
66:       ResolvedFxVanillaOption option,
67:       RatesProvider ratesProvider,
68:       BlackFxOptionSmileVolatilities volatilities) {
69: 
70:     validate(ratesProvider, volatilities);
71:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
72:     if (timeToExpiry <= 0d) {
73:       return 0d;
74:     }
75:     ResolvedFxSingle underlyingFx = option.getUnderlying();
76:     Currency ccyCounter = option.getCounterCurrency();
77:     double df = ratesProvider.discountFactor(ccyCounter, underlyingFx.getPaymentDate());
78:     FxRate forward = fxPricer.forwardFxRate(underlyingFx, ratesProvider);
79:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
80:     double forwardRate = forward.fxRate(currencyPair);
81:     double strikeRate = option.getStrike();
82:     boolean isCall = option.getPutCall().isCall();
83:     SmileDeltaParameters smileAtTime = volatilities.getSmile().smileForExpiry(timeToExpiry);
84:     double[] strikes = smileAtTime.strike(forwardRate).toArray();
85:     double[] vols = smileAtTime.getVolatility().toArray();
86:     double volAtm = vols[1];
87:     double[] x = vannaVolgaWeights(forwardRate, strikeRate, timeToExpiry, volAtm, strikes);
88:     double priceFwd = BlackFormulaRepository.price(forwardRate, strikeRate, timeToExpiry, volAtm, isCall);
89:     for (int i = 0; i < 3; i += 2) {
90:       double priceFwdAtm = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, volAtm, isCall);
91:       double priceFwdSmile = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, vols[i], isCall);
92:       priceFwd += x[i] * (priceFwdSmile - priceFwdAtm);
93:     }
94:     return df * priceFwd;
95:   }
96: 
97:   /**
98:    * Calculates the present value of the foreign exchange vanilla option product.
99:    * <p>
100:    * The present value of the product is the value on the valuation date.
101:    * It is expressed in the counter currency.
102:    * 
103:    * @param option  the option product
104:    * @param ratesProvider  the rates provider
105:    * @param volatilities  the Black volatility provider
106:    * @return the present value of the product
107:    */
108:   public CurrencyAmount presentValue(
109:       ResolvedFxVanillaOption option,
110:       RatesProvider ratesProvider,
111:       BlackFxOptionSmileVolatilities volatilities) {
112: 
113:     double price = price(option, ratesProvider, volatilities);
114:     return CurrencyAmount.of(option.getCounterCurrency(), signedNotional(option) * price);
115:   }
116: 
117:   //-------------------------------------------------------------------------
118:   /**
119:    * Calculates the present value sensitivity of the foreign exchange vanilla option product.
120:    * <p>
121:    * The present value sensitivity of the product is the sensitivity of {@link #presentValue} to
122:    * the underlying curves.
123:    * <p>
124:    * The implied strikes and weights are fixed in this sensitivity computation.
125:    * 
126:    * @param option  the option product
127:    * @param ratesProvider  the rates provider
128:    * @param volatilities  the Black volatility provider
129:    * @return the present value curve sensitivity of the product
130:    */
131:   public PointSensitivityBuilder presentValueSensitivityRatesStickyStrike(
132:       ResolvedFxVanillaOption option,
133:       RatesProvider ratesProvider,
134:       BlackFxOptionSmileVolatilities volatilities) {
135: 
136:     validate(ratesProvider, volatilities);
137:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
138:     if (timeToExpiry <= 0d) {
139:       return PointSensitivityBuilder.none();
140:     }
141:     ResolvedFxSingle underlyingFx = option.getUnderlying();
142:     Currency ccyCounter = option.getCounterCurrency();
143:     double df = ratesProvider.discountFactor(ccyCounter, underlyingFx.getPaymentDate());
144:     FxRate forward = fxPricer.forwardFxRate(underlyingFx, ratesProvider);
145:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
146:     double forwardRate = forward.fxRate(currencyPair);
147:     double strikeRate = option.getStrike();
148:     boolean isCall = option.getPutCall().isCall();
149:     SmileDeltaParameters smileAtTime = volatilities.getSmile().smileForExpiry(timeToExpiry);
150:     double[] strikes = smileAtTime.strike(forwardRate).toArray();
151:     double[] vols = smileAtTime.getVolatility().toArray();
152:     double volAtm = vols[1];
153:     double[] x = vannaVolgaWeights(forwardRate, strikeRate, timeToExpiry, volAtm, strikes);
154:     double priceFwd = BlackFormulaRepository.price(forwardRate, strikeRate, timeToExpiry, volAtm, isCall);
155:     double deltaFwd = BlackFormulaRepository.delta(forwardRate, strikeRate, timeToExpiry, volAtm, isCall);
156:     for (int i = 0; i < 3; i += 2) {
157:       double priceFwdAtm = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, volAtm, isCall);
158:       double priceFwdSmile = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, vols[i], isCall);
159:       priceFwd += x[i] * (priceFwdSmile - priceFwdAtm);
160:       double deltaFwdAtm = BlackFormulaRepository.delta(forwardRate, strikes[i], timeToExpiry, volAtm, isCall);
161:       double deltaFwdSmile = BlackFormulaRepository.delta(forwardRate, strikes[i], timeToExpiry, vols[i], isCall);
162:       deltaFwd += x[i] * (deltaFwdSmile - deltaFwdAtm);
163:     }
164:     double signedNotional = signedNotional(option);
165:     PointSensitivityBuilder dfSensi = ratesProvider.discountFactors(ccyCounter)
166:         .zeroRatePointSensitivity(underlyingFx.getPaymentDate()).multipliedBy(priceFwd * signedNotional);
167:     PointSensitivityBuilder fwdSensi = fxPricer.forwardFxRatePointSensitivity(
168:         option.getPutCall().isCall() ? underlyingFx : underlyingFx.inverse(), ratesProvider)
169:         .multipliedBy(df * deltaFwd * signedNotional);
170:     return dfSensi.combinedWith(fwdSensi);
171:   }
172: 
173:   /**
174:    * Computes the present value sensitivity to the black volatilities used in the pricing.
175:    * <p>
176:    * The implied strikes and weights are fixed in this sensitivity computation.
177:    * 
178:    * @param option  the option product
179:    * @param ratesProvider  the rates provider
180:    * @param volatilities  the Black volatility provider
181:    * @return the present value sensitivity
182:    */
183:   public PointSensitivityBuilder presentValueSensitivityModelParamsVolatility(
184:       ResolvedFxVanillaOption option,
185:       RatesProvider ratesProvider,
186:       BlackFxOptionSmileVolatilities volatilities) {
187: 
188:     validate(ratesProvider, volatilities);
189:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
190:     if (timeToExpiry <= 0d) {
191:       return PointSensitivityBuilder.none();
192:     }
193:     ResolvedFxSingle underlyingFx = option.getUnderlying();
194:     Currency ccyCounter = option.getCounterCurrency();
195:     double df = ratesProvider.discountFactor(ccyCounter, underlyingFx.getPaymentDate());
196:     FxRate forward = fxPricer.forwardFxRate(underlyingFx, ratesProvider);
197:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
198:     double forwardRate = forward.fxRate(currencyPair);
199:     double strikeRate = option.getStrike();
200:     SmileDeltaParameters smileAtTime = volatilities.getSmile().smileForExpiry(timeToExpiry);
201:     double[] strikes = smileAtTime.strike(forwardRate).toArray();
202:     double[] vols = smileAtTime.getVolatility().toArray();
203:     double volAtm = vols[1];
204:     double[] x = vannaVolgaWeights(forwardRate, strikeRate, timeToExpiry, volAtm, strikes);
205:     double vegaAtm = BlackFormulaRepository.vega(forwardRate, strikeRate, timeToExpiry, volAtm);
206:     double signedNotional = signedNotional(option);
207:     PointSensitivityBuilder sensiSmile = PointSensitivityBuilder.none();
208:     for (int i = 0; i < 3; i += 2) {
209:       double vegaFwdAtm = BlackFormulaRepository.vega(forwardRate, strikes[i], timeToExpiry, volAtm);
210:       vegaAtm -= x[i] * vegaFwdAtm;
211:       double vegaFwdSmile = BlackFormulaRepository.vega(forwardRate, strikes[i], timeToExpiry, vols[i]);
212:       sensiSmile = sensiSmile.combinedWith(
213:           FxOptionSensitivity.of(
214:               volatilities.getName(),
215:               currencyPair,
216:               timeToExpiry,
217:               strikes[i],
218:               forwardRate,
219:               ccyCounter,
220:               df * signedNotional * x[i] * vegaFwdSmile));
221:     }
222:     FxOptionSensitivity sensiAtm = FxOptionSensitivity.of(
223:         volatilities.getName(),
224:         currencyPair,
225:         timeToExpiry,
226:         strikes[1],
227:         forwardRate,
228:         ccyCounter,
229:         df * signedNotional * vegaAtm);
230:     return sensiAtm.combinedWith(sensiSmile);
231:   }
232: 
233:   /**
234:    * Calculates the currency exposure of the foreign exchange vanilla option product.
235:    * 
236:    * @param option  the option product
237:    * @param ratesProvider  the rates provider
238:    * @param volatilities  the Black volatility provider
239:    * @return the currency exposure
240:    */
241:   public MultiCurrencyAmount currencyExposure(
242:       ResolvedFxVanillaOption option,
243:       RatesProvider ratesProvider,
244:       BlackFxOptionSmileVolatilities volatilities) {
245: 
246:     validate(ratesProvider, volatilities);
247:     double timeToExpiry = volatilities.relativeTime(option.getExpiry());
248:     if (timeToExpiry <= 0d) {
249:       return MultiCurrencyAmount.empty();
250:     }
251:     ResolvedFxSingle underlyingFx = option.getUnderlying();
252:     Currency ccyCounter = option.getCounterCurrency();
253:     double df = ratesProvider.discountFactor(ccyCounter, underlyingFx.getPaymentDate());
254:     FxRate forward = fxPricer.forwardFxRate(underlyingFx, ratesProvider);
255:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
256:     double spot = ratesProvider.fxRate(currencyPair);
257:     double forwardRate = forward.fxRate(currencyPair);
258:     double fwdRateSpotSensitivity = fxPricer.forwardFxRateSpotSensitivity(
259:         option.getPutCall().isCall() ? underlyingFx : underlyingFx.inverse(), ratesProvider);
260:     double strikeRate = option.getStrike();
261:     boolean isCall = option.getPutCall().isCall();
262:     SmileDeltaParameters smileAtTime = volatilities.getSmile().smileForExpiry(timeToExpiry);
263:     double[] strikes = smileAtTime.strike(forwardRate).toArray();
264:     double[] vols = smileAtTime.getVolatility().toArray();
265:     double volAtm = vols[1];
266:     double[] x = vannaVolgaWeights(forwardRate, strikeRate, timeToExpiry, volAtm, strikes);
267:     double priceFwd = BlackFormulaRepository.price(forwardRate, strikeRate, timeToExpiry, volAtm, isCall);
268:     double deltaFwd = BlackFormulaRepository.delta(forwardRate, strikeRate, timeToExpiry, volAtm, isCall);
269:     for (int i = 0; i < 3; i += 2) {
270:       double priceFwdAtm = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, volAtm, isCall);
271:       double priceFwdSmile = BlackFormulaRepository.price(forwardRate, strikes[i], timeToExpiry, vols[i], isCall);
272:       priceFwd += x[i] * (priceFwdSmile - priceFwdAtm);
273:       double deltaFwdAtm = BlackFormulaRepository.delta(forwardRate, strikes[i], timeToExpiry, volAtm, isCall);
274:       double deltaFwdSmile = BlackFormulaRepository.delta(forwardRate, strikes[i], timeToExpiry, vols[i], isCall);
275:       deltaFwd += x[i] * (deltaFwdSmile - deltaFwdAtm);
276:     }
277:     double price = df * priceFwd;
278:     double delta = df * deltaFwd * fwdRateSpotSensitivity;
279:     double signedNotional = signedNotional(option);
280:     CurrencyAmount domestic = CurrencyAmount.of(currencyPair.getCounter(), (price - delta * spot) * signedNotional);
281:     CurrencyAmount foreign = CurrencyAmount.of(currencyPair.getBase(), delta * signedNotional);
282:     return MultiCurrencyAmount.of(domestic, foreign);
283:   }
284: 
285:   //-------------------------------------------------------------------------
286:   // signed notional amount to computed present value and value Greeks
287:   private double signedNotional(ResolvedFxVanillaOption option) {
288:     return (option.getLongShort().isLong() ? 1d : -1d) *
289:         Math.abs(option.getUnderlying().getBaseCurrencyPayment().getAmount());
290:   }
291: 
292:   private double[] vannaVolgaWeights(
293:       double forward,
294:       double strike,
295:       double timeToExpiry,
296:       double volATM,
297:       double[] strikesReference) {
298: 
299:     double lnk21 = Math.log(strikesReference[1] / strikesReference[0]);
300:     double lnk31 = Math.log(strikesReference[2] / strikesReference[0]);
301:     double lnk32 = Math.log(strikesReference[2] / strikesReference[1]);
302:     double[] lnk = new double[3];
303:     for (int loopvv = 0; loopvv < 3; loopvv++) {
304:       lnk[loopvv] = Math.log(strikesReference[loopvv] / strike);
305:     }
306:     double[] x = new double[3];
307:     double vega0 = BlackFormulaRepository.vega(forward, strikesReference[0], timeToExpiry, volATM);
308:     double vegaFlat = BlackFormulaRepository.vega(forward, strike, timeToExpiry, volATM);
309:     double vega2 = BlackFormulaRepository.vega(forward, strikesReference[2], timeToExpiry, volATM);
310:     x[0] = vegaFlat * lnk[1] * lnk[2] / (vega0 * lnk21 * lnk31);
311:     x[2] = vegaFlat * lnk[0] * lnk[1] / (vega2 * lnk31 * lnk32);
312:     return x;
313:   }
314: 
315:   private void validate(RatesProvider ratesProvider, BlackFxOptionSmileVolatilities volatilities) {
316:     ArgChecker.isTrue(volatilities.getValuationDateTime().toLocalDate().equals(ratesProvider.getValuationDate()),
317:         "volatility and rate data must be for the same date");
318:     ArgChecker.isTrue(volatilities.getSmile().getStrikeCount() == 3, "the number of data points must be 3");
319:   }
320: }
