11: import java.time.LocalDate;
12: 
13: import com.opengamma.strata.basics.currency.CurrencyAmount;
14: import com.opengamma.strata.basics.currency.CurrencyPair;
15: import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
16: import com.opengamma.strata.collect.ArgChecker;
