21: import com.opengamma.strata.market.param.CurrencyParameterSensitivities;
22: import com.opengamma.strata.market.sensitivity.PointSensitivities;
23: import com.opengamma.strata.measure.rate.RatesScenarioMarketData;
24: import com.opengamma.strata.pricer.fxopt.BlackFxOptionSmileVolatilities;
25: import com.opengamma.strata.pricer.fxopt.BlackFxOptionVolatilities;
26: import com.opengamma.strata.pricer.fxopt.BlackFxVanillaOptionTradePricer;
27: import com.opengamma.strata.pricer.fxopt.FxOptionVolatilities;
28: import com.opengamma.strata.pricer.fxopt.VannaVolgaFxVanillaOptionTradePricer;
29: import com.opengamma.strata.pricer.rate.RatesProvider;
30: import com.opengamma.strata.pricer.sensitivity.MarketQuoteSensitivityCalculator;
31: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOptionTrade;
