33: /**
34:  * Multi-scenario measure calculations for FX vanilla option trades.
35:  * <p>
36:  * Each method corresponds to a measure, typically calculated by one or more calls to the pricer.
37:  */
38: final class FxVanillaOptionMeasureCalculations {
39: 
40:   /**
41:    * Default implementation.
42:    */
43:   public static final FxVanillaOptionMeasureCalculations DEFAULT = new FxVanillaOptionMeasureCalculations(
44:       BlackFxVanillaOptionTradePricer.DEFAULT,
45:       VannaVolgaFxVanillaOptionTradePricer.DEFAULT);
46:   /**
47:    * The market quote sensitivity calculator.
48:    */
49:   private static final MarketQuoteSensitivityCalculator MARKET_QUOTE_SENS = MarketQuoteSensitivityCalculator.DEFAULT;
50:   /**
51:    * One basis point, expressed as a {@code double}.
52:    */
53:   private static final double ONE_BASIS_POINT = 1e-4;
54: 
55:   /**
56:    * Pricer for {@link ResolvedFxVanillaOptionTrade}.
57:    */
58:   private final BlackFxVanillaOptionTradePricer blackPricer;
59:   /**
60:    * Pricer for {@link ResolvedFxVanillaOptionTrade}.
61:    */
62:   private final VannaVolgaFxVanillaOptionTradePricer vannaVolgaPricer;
63: 
64:   /**
65:    * Creates an instance.
66:    * 
67:    * @param blackPricer  the pricer for {@link ResolvedFxVanillaOptionTrade} using Black
68:    * @param vannaVolgaPricer  the pricer for {@link ResolvedFxVanillaOptionTrade} using Vanna-Volga
69:    */
70:   FxVanillaOptionMeasureCalculations(
71:       BlackFxVanillaOptionTradePricer blackPricer,
72:       VannaVolgaFxVanillaOptionTradePricer vannaVolgaPricer) {
73:     this.blackPricer = ArgChecker.notNull(blackPricer, "blackPricer");
74:     this.vannaVolgaPricer = ArgChecker.notNull(vannaVolgaPricer, "vannaVolgaPricer");
75:   }
76: 
77:   //-------------------------------------------------------------------------
78:   // calculates present value for all scenarios
79:   MultiCurrencyScenarioArray presentValue(
80:       ResolvedFxVanillaOptionTrade trade,
81:       RatesScenarioMarketData ratesMarketData,
82:       FxOptionScenarioMarketData optionMarketData,
83:       FxVanillaOptionMethod method) {
84: 
85:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
86:     return MultiCurrencyScenarioArray.of(
87:         ratesMarketData.getScenarioCount(),
88:         i -> presentValue(
89:             trade,
90:             ratesMarketData.scenario(i).ratesProvider(),
91:             optionMarketData.scenario(i).volatilities(currencyPair),
92:             method));
93:   }
94: 
95:   // present value for one scenario
96:   MultiCurrencyAmount presentValue(
97:       ResolvedFxVanillaOptionTrade trade,
98:       RatesProvider ratesProvider,
99:       FxOptionVolatilities volatilities,
100:       FxVanillaOptionMethod method) {
101: 
102:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
103:       return vannaVolgaPricer.presentValue(trade, ratesProvider, checkVannaVolgaVolatilities(volatilities));
104:     } else {
105:       return blackPricer.presentValue(trade, ratesProvider, checkBlackVolatilities(volatilities));
106:     }
107:   }
108: 
109:   //-------------------------------------------------------------------------
110:   // calculates calibrated sum PV01 for all scenarios
111:   MultiCurrencyScenarioArray pv01RatesCalibratedSum(
112:       ResolvedFxVanillaOptionTrade trade,
113:       RatesScenarioMarketData ratesMarketData,
114:       FxOptionScenarioMarketData optionMarketData,
115:       FxVanillaOptionMethod method) {
116: 
117:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
118:     return MultiCurrencyScenarioArray.of(
119:         ratesMarketData.getScenarioCount(),
120:         i -> pv01RatesCalibratedSum(
121:             trade,
122:             ratesMarketData.scenario(i).ratesProvider(),
123:             optionMarketData.scenario(i).volatilities(currencyPair),
124:             method));
125:   }
126: 
127:   // calibrated sum PV01 for one scenario
128:   MultiCurrencyAmount pv01RatesCalibratedSum(
129:       ResolvedFxVanillaOptionTrade trade,
130:       RatesProvider ratesProvider,
131:       FxOptionVolatilities volatilities,
132:       FxVanillaOptionMethod method) {
133: 
134:     CurrencyParameterSensitivities paramSens = pointSensitivity(trade, ratesProvider, volatilities, method);
135:     return paramSens.total().multipliedBy(ONE_BASIS_POINT);
136:   }
137: 
138:   //-------------------------------------------------------------------------
139:   // calculates calibrated bucketed PV01 for all scenarios
140:   ScenarioArray<CurrencyParameterSensitivities> pv01RatesCalibratedBucketed(
141:       ResolvedFxVanillaOptionTrade trade,
142:       RatesScenarioMarketData ratesMarketData,
143:       FxOptionScenarioMarketData optionMarketData,
144:       FxVanillaOptionMethod method) {
145: 
146:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
147:     return ScenarioArray.of(
148:         ratesMarketData.getScenarioCount(),
149:         i -> pv01RatesCalibratedBucketed(
150:             trade,
151:             ratesMarketData.scenario(i).ratesProvider(),
152:             optionMarketData.scenario(i).volatilities(currencyPair),
153:             method));
154:   }
155: 
156:   // calibrated bucketed PV01 for one scenario
157:   CurrencyParameterSensitivities pv01RatesCalibratedBucketed(
158:       ResolvedFxVanillaOptionTrade trade,
159:       RatesProvider ratesProvider,
160:       FxOptionVolatilities volatilities,
161:       FxVanillaOptionMethod method) {
162: 
163:     CurrencyParameterSensitivities paramSens = pointSensitivity(trade, ratesProvider, volatilities, method);
164:     return paramSens.multipliedBy(ONE_BASIS_POINT);
165:   }
166: 
167:   //-------------------------------------------------------------------------
168:   // calculates market quote sum PV01 for all scenarios
169:   MultiCurrencyScenarioArray pv01RatesMarketQuoteSum(
170:       ResolvedFxVanillaOptionTrade trade,
171:       RatesScenarioMarketData ratesMarketData,
172:       FxOptionScenarioMarketData optionMarketData,
173:       FxVanillaOptionMethod method) {
174: 
175:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
176:     return MultiCurrencyScenarioArray.of(
177:         ratesMarketData.getScenarioCount(),
178:         i -> pv01RatesMarketQuoteSum(
179:             trade,
180:             ratesMarketData.scenario(i).ratesProvider(),
181:             optionMarketData.scenario(i).volatilities(currencyPair),
182:             method));
183:   }
184: 
185:   // market quote sum PV01 for one scenario
186:   MultiCurrencyAmount pv01RatesMarketQuoteSum(
187:       ResolvedFxVanillaOptionTrade trade,
188:       RatesProvider ratesProvider,
189:       FxOptionVolatilities volatilities,
190:       FxVanillaOptionMethod method) {
191: 
192:     CurrencyParameterSensitivities paramSens = pointSensitivity(trade, ratesProvider, volatilities, method);
193:     return MARKET_QUOTE_SENS.sensitivity(paramSens, ratesProvider).total().multipliedBy(ONE_BASIS_POINT);
194:   }
195: 
196:   //-------------------------------------------------------------------------
197:   // calculates market quote bucketed PV01 for all scenarios
198:   ScenarioArray<CurrencyParameterSensitivities> pv01RatesMarketQuoteBucketed(
199:       ResolvedFxVanillaOptionTrade trade,
200:       RatesScenarioMarketData ratesMarketData,
201:       FxOptionScenarioMarketData optionMarketData,
202:       FxVanillaOptionMethod method) {
203: 
204:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
205:     return ScenarioArray.of(
206:         ratesMarketData.getScenarioCount(),
207:         i -> pv01RatesMarketQuoteBucketed(
208:             trade,
209:             ratesMarketData.scenario(i).ratesProvider(),
210:             optionMarketData.scenario(i).volatilities(currencyPair),
211:             method));
212:   }
213: 
214:   // market quote bucketed PV01 for one scenario
215:   CurrencyParameterSensitivities pv01RatesMarketQuoteBucketed(
216:       ResolvedFxVanillaOptionTrade trade,
217:       RatesProvider ratesProvider,
218:       FxOptionVolatilities volatilities,
219:       FxVanillaOptionMethod method) {
220: 
221:     CurrencyParameterSensitivities paramSens = pointSensitivity(trade, ratesProvider, volatilities, method);
222:     return MARKET_QUOTE_SENS.sensitivity(paramSens, ratesProvider).multipliedBy(ONE_BASIS_POINT);
223:   }
224: 
225:   // point sensitivity
226:   private CurrencyParameterSensitivities pointSensitivity(
227:       ResolvedFxVanillaOptionTrade trade,
228:       RatesProvider ratesProvider,
229:       FxOptionVolatilities volatilities,
230:       FxVanillaOptionMethod method) {
231: 
232:     PointSensitivities pointSens;
233:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
234:       pointSens = vannaVolgaPricer.presentValueSensitivityRatesStickyStrike(
235:           trade, ratesProvider, checkVannaVolgaVolatilities(volatilities));
236:     } else {
237:       pointSens = blackPricer.presentValueSensitivityRatesStickyStrike(
238:           trade, ratesProvider, checkBlackVolatilities(volatilities));
239:     }
240:     return ratesProvider.parameterSensitivity(pointSens);
241:   }
242: 
243:   //-------------------------------------------------------------------------
244:   // calculates vega (present value volatility sensitivities) for all scenarios
245:   ScenarioArray<CurrencyParameterSensitivities> vegaMarketQuoteBucketed(
246:       ResolvedFxVanillaOptionTrade trade,
247:       RatesScenarioMarketData ratesMarketData,
248:       FxOptionScenarioMarketData optionMarketData,
249:       FxVanillaOptionMethod method) {
250: 
251:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
252:     return ScenarioArray.of(
253:         ratesMarketData.getScenarioCount(),
254:         i -> vegaMarketQuoteBucketed(
255:             trade,
256:             ratesMarketData.scenario(i).ratesProvider(),
257:             optionMarketData.scenario(i).volatilities(currencyPair),
258:             method));
259:   }
260: 
261:   // vega for one scenario
262:   CurrencyParameterSensitivities vegaMarketQuoteBucketed(
263:       ResolvedFxVanillaOptionTrade trade,
264:       RatesProvider ratesProvider,
265:       FxOptionVolatilities volatilities,
266:       FxVanillaOptionMethod method) {
267: 
268:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
269:       BlackFxOptionSmileVolatilities blackSmileVols = checkVannaVolgaVolatilities(volatilities);
270:       PointSensitivities pointSens =
271:           vannaVolgaPricer.presentValueSensitivityModelParamsVolatility(trade, ratesProvider, blackSmileVols);
272:       return blackSmileVols.parameterSensitivity(pointSens);
273:     } else {
274:       BlackFxOptionVolatilities blackVols = checkBlackVolatilities(volatilities);
275:       PointSensitivities pointSens =
276:           blackPricer.presentValueSensitivityModelParamsVolatility(trade, ratesProvider, blackVols);
277:       return blackVols.parameterSensitivity(pointSens);
278:     }
279:   }
280: 
281:   //-------------------------------------------------------------------------
282:   // calculates currency exposure for all scenarios
283:   MultiCurrencyScenarioArray currencyExposure(
284:       ResolvedFxVanillaOptionTrade trade,
285:       RatesScenarioMarketData ratesMarketData,
286:       FxOptionScenarioMarketData optionMarketData,
287:       FxVanillaOptionMethod method) {
288: 
289:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
290:     return MultiCurrencyScenarioArray.of(
291:         ratesMarketData.getScenarioCount(),
292:         i -> currencyExposure(
293:             trade,
294:             ratesMarketData.scenario(i).ratesProvider(),
295:             optionMarketData.scenario(i).volatilities(currencyPair),
296:             method));
297:   }
298: 
299:   // currency exposure for one scenario
300:   MultiCurrencyAmount currencyExposure(
301:       ResolvedFxVanillaOptionTrade trade,
302:       RatesProvider ratesProvider,
303:       FxOptionVolatilities volatilities,
304:       FxVanillaOptionMethod method) {
305: 
306:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
307:       return vannaVolgaPricer.currencyExposure(trade, ratesProvider, checkVannaVolgaVolatilities(volatilities));
308:     } else {
309:       return blackPricer.currencyExposure(trade, ratesProvider, checkBlackVolatilities(volatilities));
310:     }
311:   }
312: 
313:   //-------------------------------------------------------------------------
314:   // calculates delta for all scenarios
315:   DoubleScenarioArray delta(
316:       ResolvedFxVanillaOptionTrade trade,
317:       RatesScenarioMarketData ratesMarketData,
318:       FxOptionScenarioMarketData optionMarketData,
319:       FxVanillaOptionMethod method) {
320: 
321:     CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
322:     return DoubleScenarioArray.of(
323:         ratesMarketData.getScenarioCount(),
324:         i -> delta(
325:             trade,
326:             ratesMarketData.scenario(i).ratesProvider(),
327:             optionMarketData.scenario(i).volatilities(currencyPair),
328:             method));
329:   }
330: 
331:   // delta for one scenario
332:   double delta(
333:       ResolvedFxVanillaOptionTrade trade,
334:       RatesProvider ratesProvider,
335:       FxOptionVolatilities volatilities,
336:       FxVanillaOptionMethod method) {
337: 
338:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
339:       throw new IllegalArgumentException(
340:           "FX vanilla option Vanna Volga pricer does not currently support delta calculation");
341:     } else {
342:       return blackPricer.delta(trade, ratesProvider, checkBlackVolatilities(volatilities));
343:     }
344:   }
345: 
346:   //-------------------------------------------------------------------------
347:   // calculates current cash for all scenarios
348:   CurrencyScenarioArray currentCash(
349:       ResolvedFxVanillaOptionTrade trade,
350:       RatesScenarioMarketData ratesMarketData,
351:       FxOptionScenarioMarketData optionMarketData,
352:       FxVanillaOptionMethod method) {
353: 
354:     return CurrencyScenarioArray.of(
355:         ratesMarketData.getScenarioCount(),
356:         i -> currentCash(
357:             trade,
358:             ratesMarketData.scenario(i).getValuationDate(),
359:             method));
360:   }
361: 
362:   // current cash for one scenario
363:   CurrencyAmount currentCash(
364:       ResolvedFxVanillaOptionTrade trade,
365:       LocalDate valuationDate,
366:       FxVanillaOptionMethod method) {
367: 
368:     if (method == FxVanillaOptionMethod.VANNA_VOLGA) {
369:       return vannaVolgaPricer.currentCash(trade, valuationDate);
370:     } else {
371:       return blackPricer.currentCash(trade, valuationDate);
372:     }
373:   }
374: 
375: }
