6: package com.opengamma.strata.measure.fxopt;
7: 
8: import java.util.HashMap;
9: import java.util.Map;
10: import java.util.Optional;
11: import java.util.Set;
12: 
13: import com.google.common.collect.ImmutableMap;
14: import com.google.common.collect.ImmutableSet;
15: import com.opengamma.strata.basics.ReferenceData;
16: import com.opengamma.strata.basics.currency.Currency;
17: import com.opengamma.strata.basics.currency.CurrencyPair;
18: import com.opengamma.strata.calc.Measure;
19: import com.opengamma.strata.calc.runner.CalculationFunction;
20: import com.opengamma.strata.calc.runner.CalculationParameters;
21: import com.opengamma.strata.calc.runner.FunctionRequirements;
22: import com.opengamma.strata.collect.result.FailureReason;
23: import com.opengamma.strata.collect.result.Result;
24: import com.opengamma.strata.data.scenario.ScenarioMarketData;
25: import com.opengamma.strata.measure.Measures;
26: import com.opengamma.strata.measure.rate.RatesMarketDataLookup;
27: import com.opengamma.strata.measure.rate.RatesScenarioMarketData;
28: import com.opengamma.strata.product.fxopt.FxVanillaOption;
29: import com.opengamma.strata.product.fxopt.FxVanillaOptionTrade;
30: import com.opengamma.strata.product.fxopt.ResolvedFxVanillaOptionTrade;
31: 
32: /**
33:  * Perform calculations on an FX vanilla option trade for each of a set of scenarios.
34:  * <p>
35:  * This uses Black FX option volatilities, which must be specified using {@link FxOptionMarketDataLookup}.
36:  * An instance of {@link RatesMarketDataLookup} must also be specified.
37:  * <p>
38:  * Two pricing methods are available, 'Black' and 'VannaVolga'.
39:  * By default, 'Black' will be used. To control the method, pass an instance of
40:  * {@link FxVanillaOptionMethod} in the calculation parameters.
41:  * <p>
42:  * The supported built-in measures are:
43:  * <ul>
44:  *   <li>{@linkplain Measures#PRESENT_VALUE Present value}
45:  *   <li>{@linkplain Measures#PV01_CALIBRATED_SUM PV01 calibrated sum on rate curves}
46:  *   <li>{@linkplain Measures#PV01_CALIBRATED_BUCKETED PV01 calibrated bucketed on rate curves}
47:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_SUM PV01 market quote sum on rate curves}
48:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_BUCKETED PV01 market quote bucketed on rate curves}
49:  *   <li>{@linkplain Measures#CURRENCY_EXPOSURE Currency exposure}
50:  *   <li>{@linkplain Measures#CURRENT_CASH Current cash}
51:  *   <li>{@linkplain Measures#VEGA_MARKET_QUOTE_BUCKETED Vega market quote bucketed on volatility curves/surfaces}
52:  *   <li>{@linkplain Measures#RESOLVED_TARGET Resolved trade}
53:  * </ul>
54:  * <p>
55:  * The "natural" currency is the market convention base currency of the underlying FX.
56:  */
57: public class FxVanillaOptionTradeCalculationFunction
58:     implements CalculationFunction<FxVanillaOptionTrade> {
59: 
60:   /**
61:    * The calculations by measure.
62:    */
63:   private static final ImmutableMap<Measure, SingleMeasureCalculation> CALCULATORS =
64:       ImmutableMap.<Measure, SingleMeasureCalculation>builder()
65:           .put(Measures.PRESENT_VALUE, FxVanillaOptionMeasureCalculations.DEFAULT::presentValue)
66:           .put(Measures.PV01_CALIBRATED_SUM, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesCalibratedSum)
67:           .put(Measures.PV01_CALIBRATED_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesCalibratedBucketed)
68:           .put(Measures.PV01_MARKET_QUOTE_SUM, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesMarketQuoteSum)
69:           .put(Measures.PV01_MARKET_QUOTE_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesMarketQuoteBucketed)
70:           .put(Measures.CURRENCY_EXPOSURE, FxVanillaOptionMeasureCalculations.DEFAULT::currencyExposure)
71:           .put(Measures.OPTION_DELTA, FxVanillaOptionMeasureCalculations.DEFAULT::delta)
72:           .put(Measures.CURRENT_CASH, FxVanillaOptionMeasureCalculations.DEFAULT::currentCash)
73:           .put(Measures.VEGA_MARKET_QUOTE_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::vegaMarketQuoteBucketed)
74:           .put(Measures.RESOLVED_TARGET, (rt, smd, m, meth) -> rt)
75:           .build();
76: 
77:   private static final ImmutableSet<Measure> MEASURES = CALCULATORS.keySet();
78: 
79:   /**
80:    * Creates an instance.
81:    */
82:   public FxVanillaOptionTradeCalculationFunction() {
83:   }
84: 
85:   //-------------------------------------------------------------------------
86:   @Override
87:   public Class<FxVanillaOptionTrade> targetType() {
88:     return FxVanillaOptionTrade.class;
89:   }
90: 
91:   @Override
92:   public Set<Measure> supportedMeasures() {
93:     return MEASURES;
94:   }
95: 
96:   @Override
97:   public Optional<String> identifier(FxVanillaOptionTrade target) {
98:     return target.getInfo().getId().map(id -> id.toString());
99:   }
100: 
101:   @Override
102:   public Currency naturalCurrency(FxVanillaOptionTrade trade, ReferenceData refData) {
103:     return trade.getProduct().getCurrencyPair().getBase();
104:   }
105: 
106:   //-------------------------------------------------------------------------
107:   @Override
108:   public FunctionRequirements requirements(
109:       FxVanillaOptionTrade trade,
110:       Set<Measure> measures,
111:       CalculationParameters parameters,
112:       ReferenceData refData) {
113: 
114:     // extract data from product
115:     FxVanillaOption product = trade.getProduct();
116:     CurrencyPair currencyPair = product.getCurrencyPair();
117: 
118:     // use lookup to build requirements
119:     RatesMarketDataLookup ratesLookup = parameters.getParameter(RatesMarketDataLookup.class);
120:     FunctionRequirements ratesReqs = ratesLookup.requirements(
121:         ImmutableSet.of(currencyPair.getBase(), currencyPair.getCounter()));
122:     FxOptionMarketDataLookup optionLookup = parameters.getParameter(FxOptionMarketDataLookup.class);
123:     FunctionRequirements optionReqs = optionLookup.requirements(currencyPair);
124:     return ratesReqs.combinedWith(optionReqs);
125:   }
126: 
127:   //-------------------------------------------------------------------------
128:   @Override
129:   public Map<Measure, Result<?>> calculate(
130:       FxVanillaOptionTrade trade,
131:       Set<Measure> measures,
132:       CalculationParameters parameters,
133:       ScenarioMarketData scenarioMarketData,
134:       ReferenceData refData) {
135: 
136:     // expand the trade once for all measures and all scenarios
137:     ResolvedFxVanillaOptionTrade resolved = trade.resolve(refData);
138:     RatesMarketDataLookup ratesLookup = parameters.getParameter(RatesMarketDataLookup.class);
139:     RatesScenarioMarketData ratesMarketData = ratesLookup.marketDataView(scenarioMarketData);
140:     FxOptionMarketDataLookup optionLookup = parameters.getParameter(FxOptionMarketDataLookup.class);
141:     FxOptionScenarioMarketData optionMarketData = optionLookup.marketDataView(scenarioMarketData);
142:     FxVanillaOptionMethod method = parameters.findParameter(FxVanillaOptionMethod.class).orElse(FxVanillaOptionMethod.BLACK);
143: 
144:     // loop around measures, calculating all scenarios for one measure
145:     Map<Measure, Result<?>> results = new HashMap<>();
146:     for (Measure measure : measures) {
147:       results.put(measure, calculate(measure, resolved, ratesMarketData, optionMarketData, method));
148:     }
149:     return results;
150:   }
151: 
152:   // calculate one measure
153:   private Result<?> calculate(
154:       Measure measure,
155:       ResolvedFxVanillaOptionTrade trade,
156:       RatesScenarioMarketData ratesMarketData,
157:       FxOptionScenarioMarketData optionMarketData,
158:       FxVanillaOptionMethod method) {
159: 
160:     SingleMeasureCalculation calculator = CALCULATORS.get(measure);
161:     if (calculator == null) {
162:       return Result.failure(FailureReason.UNSUPPORTED, "Unsupported measure for FxVanillaOptionTrade: {}", measure);
163:     }
164:     return Result.of(() -> calculator.calculate(trade, ratesMarketData, optionMarketData, method));
165:   }
166: 
167:   //-------------------------------------------------------------------------
168:   @FunctionalInterface
169:   interface SingleMeasureCalculation {
170:     public abstract Object calculate(
171:         ResolvedFxVanillaOptionTrade trade,
172:         RatesScenarioMarketData ratesMarketData,
173:         FxOptionScenarioMarketData optionMarketData,
174:         FxVanillaOptionMethod method);
175:   }
176: 
177: }
