55: /**
56:  * Handles the CSV file format for FX vanilla option trades.
57:  */
58: class FxVanillaOptionTradeCsvPlugin implements TradeCsvParserPlugin, TradeCsvWriterPlugin<FxVanillaOptionTrade> {
59: 
60:   /**
61:    * The singleton instance of the plugin.
62:    */
63:   public static final FxVanillaOptionTradeCsvPlugin INSTANCE = new FxVanillaOptionTradeCsvPlugin();
64: 
65:   /** The headers. */
66:   private static final ImmutableSet<String> HEADERS = ImmutableSet.of(
67:       LONG_SHORT_FIELD,
68:       PUT_CALL_FIELD,
69:       STRIKE_FIELD,
70:       EXPIRY_DATE_FIELD,
71:       EXPIRY_TIME_FIELD,
72:       EXPIRY_ZONE_FIELD,
73:       PREMIUM_DATE_FIELD,
74:       PREMIUM_DATE_CNV_FIELD,
75:       PREMIUM_DATE_CAL_FIELD,
76:       PREMIUM_DIRECTION_FIELD,
77:       PREMIUM_CURRENCY_FIELD,
78:       PREMIUM_AMOUNT_FIELD,
79:       LEG_1_CURRENCY_FIELD,
80:       LEG_1_NOTIONAL_FIELD,
81:       LEG_2_CURRENCY_FIELD,
82:       PAYMENT_DATE_FIELD,
83:       PAYMENT_DATE_CNV_FIELD,
84:       PAYMENT_DATE_CAL_FIELD);
85: 
86:   //-------------------------------------------------------------------------
87:   @Override
88:   public Set<String> tradeTypeNames() {
89:     return ImmutableSet.of("FXVANILLAOPTION", "FX VANILLA OPTION");
90:   }
91: 
92:   @Override
93:   public Optional<Trade> parseTrade(
94:       Class<?> requiredJavaType,
95:       CsvRow baseRow,
96:       List<CsvRow> additionalRows,
97:       TradeInfo info,
98:       TradeCsvInfoResolver resolver) {
99: 
100:     if (requiredJavaType.isAssignableFrom(FxVanillaOptionTrade.class)) {
101:       return Optional.of(resolver.parseFxVanillaOptionTrade(baseRow, info));
102:     }
103:     return Optional.empty();
104:   }
105: 
106:   @Override
107:   public String getName() {
108:     return FxVanillaOptionTrade.class.getSimpleName();
109:   }
110: 
111:   @Override
112:   public Set<Class<?>> supportedTradeTypes() {
113:     return ImmutableSet.of(FxVanillaOptionTrade.class);
114:   }
115: 
116:   //-------------------------------------------------------------------------
117:   /**
118:    * Parses the data from a CSV row.
119:    *
120:    * @param row  the CSV row object
121:    * @param info  the trade info object
122:    * @param resolver  the resolver used to parse additional information
123:    * @return the parsed trade
124:    */
125:   static FxVanillaOptionTrade parse(CsvRow row, TradeInfo info, TradeCsvInfoResolver resolver) {
126:     if (row.findValue(PUT_CALL_FIELD).isPresent()) {
127:       FxVanillaOptionTrade trade = parseRow(row, info);
128:       return resolver.completeTrade(row, trade);
129:     }
130:     FxSingleTrade singleTrade = FxSingleTradeCsvPlugin.parseRow(row, info);
131:     FxVanillaOptionTrade trade = parseRow(row, info, singleTrade.getProduct());
132:     return resolver.completeTrade(row, trade);
133:   }
134: 
135:   // parses the trade from the underlying FX single
136:   private static FxVanillaOptionTrade parseRow(CsvRow row, TradeInfo info, FxSingle underlying) {
137:     LongShort longShort = row.getValue(LONG_SHORT_FIELD, LoaderUtils::parseLongShort);
138:     LocalDate expiryDate = row.getValue(EXPIRY_DATE_FIELD, LoaderUtils::parseDate);
139:     LocalTime expiryTime = row.getValue(EXPIRY_TIME_FIELD, LoaderUtils::parseTime);
140:     ZoneId expiryZone = row.getValue(EXPIRY_ZONE_FIELD, LoaderUtils::parseZoneId);
141: 
142:     FxVanillaOption option = FxVanillaOption.builder()
143:         .longShort(longShort)
144:         .expiryDate(expiryDate)
145:         .expiryTime(expiryTime)
146:         .expiryZone(expiryZone)
147:         .underlying(underlying)
148:         .build();
149:     return FxVanillaOptionTrade.builder()
150:         .info(info)
151:         .product(option)
152:         .premium(CsvLoaderUtils.tryParsePremiumFromDefaultFields(row)
153:             .orElse(AdjustablePayment.of(option.getCurrencyPair().getBase(), 0d, expiryDate)))
154:         .build();
155:   }
156: 
157:   // parse the trade from the currency pairs, base currency notional, and put/call
158:   private static FxVanillaOptionTrade parseRow(CsvRow row, TradeInfo info) {
159:     LongShort longShort = row.getValue(LONG_SHORT_FIELD, LoaderUtils::parseLongShort);
160:     LocalDate expiryDate = row.getValue(EXPIRY_DATE_FIELD, LoaderUtils::parseDate);
161:     LocalTime expiryTime = row.getValue(EXPIRY_TIME_FIELD, LoaderUtils::parseTime);
162:     ZoneId expiryZone = row.getValue(EXPIRY_ZONE_FIELD, LoaderUtils::parseZoneId);
163:     PutCall putCall = row.getValue(PUT_CALL_FIELD, LoaderUtils::parsePutCall);
164:     Currency ccy1 = row.getValue(LEG_1_CURRENCY_FIELD, LoaderUtils::parseCurrency);
165:     Currency ccy2 = row.getValue(LEG_2_CURRENCY_FIELD, LoaderUtils::parseCurrency);
166:     LocalDate paymentDate = row.getValue(PAYMENT_DATE_FIELD, LoaderUtils::parseDate);
167:     double notional1 = row.getValue(LEG_1_NOTIONAL_FIELD, LoaderUtils::parseDouble);
168: 
169:     double strike = parseStrike(row, notional1);
170: 
171:     Optional<BusinessDayAdjustment> paymentAdj = CsvLoaderUtils
172:         .parseBusinessDayAdjustment(row, PAYMENT_DATE_CNV_FIELD, PAYMENT_DATE_CAL_FIELD)
173:         .filter(adj -> !adj.equals(BusinessDayAdjustment.NONE));
174: 
175:     ZonedDateTime expiry = expiryDate.atTime(expiryTime).atZone(expiryZone);
176:     CurrencyPair ccyPair = CurrencyPair.of(ccy1, ccy2);
177:     FxVanillaOption option = paymentAdj
178:         .map(adj -> FxVanillaOption.of(longShort, expiry, ccyPair, putCall, strike, notional1, paymentDate, adj))
179:         .orElseGet(() -> FxVanillaOption.of(longShort, expiry, ccyPair, putCall, strike, notional1, paymentDate));
180:     return FxVanillaOptionTrade.builder()
181:         .info(info)
182:         .product(option)
183:         .premium(CsvLoaderUtils.tryParsePremiumFromDefaultFields(row)
184:             .orElse(AdjustablePayment.of(option.getCurrencyPair().getBase(), 0d, expiryDate)))
185:         .build();
186:   }
187: 
188:   private static double parseStrike(CsvRow row, double notional1) {
189:     Optional<Double> strikeOpt = row.findValue(STRIKE_FIELD, LoaderUtils::parseDouble);
190:     if (strikeOpt.isPresent()) {
191:       return strikeOpt.get();
192:     } else {
193:       double notional2 = row.getValue(LEG_2_NOTIONAL_FIELD, LoaderUtils::parseDouble);
194:       return Math.abs(notional2 / notional1);
195:     }
196:   }
197: 
198:   //-------------------------------------------------------------------------
199:   @Override
200:   public Set<String> headers(List<FxVanillaOptionTrade> trades) {
201:     return HEADERS;
202:   }
203: 
204:   @Override
205:   public void writeCsv(CsvRowOutputWithHeaders csv, FxVanillaOptionTrade trade) {
206:     csv.writeCell(TRADE_TYPE_FIELD, "FxVanillaOption");
207:     writeFxVanillaOption(csv, trade.getProduct());
208:     CsvWriterUtils.writePremiumFields(csv, trade.getPremium());
209:     csv.writeNewLine();
210:   }
211: 
212:   protected void writeFxVanillaOption(CsvOutput.CsvRowOutputWithHeaders csv, FxVanillaOption product) {
213:     FxSingle underlying = product.getUnderlying();
214:     PutCall putCall = underlying.getCounterCurrencyPayment().getAmount() > 0d ? PutCall.PUT : PutCall.CALL;
215:     double strike = Math.abs(underlying.getCounterCurrencyPayment().getAmount() /
216:         underlying.getBaseCurrencyPayment().getAmount());
217:     csv.writeCell(LONG_SHORT_FIELD, product.getLongShort());
218:     csv.writeCell(PUT_CALL_FIELD, putCall);
219:     csv.writeCell(STRIKE_FIELD, strike);
220:     csv.writeCell(EXPIRY_DATE_FIELD, product.getExpiryDate());
221:     csv.writeCell(EXPIRY_TIME_FIELD, product.getExpiryTime());
222:     csv.writeCell(EXPIRY_ZONE_FIELD, product.getExpiryZone());
223:     csv.writeCell(LEG_1_CURRENCY_FIELD, underlying.getBaseCurrencyPayment().getCurrency());
224:     csv.writeCell(LEG_1_NOTIONAL_FIELD, Math.abs(underlying.getBaseCurrencyPayment().getAmount()));
225:     csv.writeCell(LEG_2_CURRENCY_FIELD, underlying.getCounterCurrencyPayment().getCurrency());
226:     csv.writeCell(PAYMENT_DATE_FIELD, underlying.getBaseCurrencyPayment().getDate());
227:     underlying.getPaymentDateAdjustment().ifPresent(bda -> {
228:       csv.writeCell(PAYMENT_DATE_CAL_FIELD, bda.getCalendar());
229:       csv.writeCell(PAYMENT_DATE_CNV_FIELD, bda.getConvention());
230:     });
231:   }
232: 
233:   //-------------------------------------------------------------------------
234:   // Restricted constructor.
235:   private FxVanillaOptionTradeCsvPlugin() {
236:   }
237: 
238: }
