      LongShort longShort,
      ZonedDateTime expiry,
      CurrencyPair currencyPair,
      PutCall putCall,
      double strike,
      double baseNotional,
      LocalDate paymentDate,
      BusinessDayAdjustment paymentDateAdjustment) {

