/**
 * Pricer for FX European option trades with a Vanna-Volga method.
 * <p>
 * The volatilities are expressed using {@code BlackFxOptionSmileVolatilities}.
 * Each smile of the term structure consists of 3 data points, where the middle point corresponds to ATM volatility.
 */
public class VannaVolgaFxEuropeanOptionTradePricer {

  /**
   * Default implementation.
   */
  public static final VannaVolgaFxEuropeanOptionTradePricer DEFAULT = new VannaVolgaFxEuropeanOptionTradePricer(
      VannaVolgaFxEuropeanOptionProductPricer.DEFAULT,
      DiscountingPaymentPricer.DEFAULT);

  /**
   * Pricer for {@link ResolvedFxSingleBarrierOption}.
   */
  private final VannaVolgaFxEuropeanOptionProductPricer productPricer;
  /**
   * Pricer for {@link Payment}.
   */
  private final DiscountingPaymentPricer paymentPricer;

  /**
   * Creates an instance.
   *
   * @param productPricer  the pricer for {@link ResolvedFxEuropeanOption}
   * @param paymentPricer  the pricer for {@link Payment}
   */
  public VannaVolgaFxEuropeanOptionTradePricer(
