133:     Currency ccyCounter = underlyingFx.getCounterCurrencyPayment().getCurrency();
134:     if (alreadyTouched(todayFx, barrier)) {
135:       if (barrier.getKnockType().isKnockIn()) {
136:         return VANILLA_OPTION_PRICER.price(underlyingOption, ratesProvider, volatilities);
137:       } else if (option.getRebate().isPresent()) {
138:         CurrencyAmount rebate = option.getRebate().get();
139:         DaysAdjustment spotLag = spotAdjustment(currencyPair);
140:         LocalDate paymentDate = spotLag.adjust(ratesProvider.getValuationDate(), ReferenceData.standard());
141:         double rebatePrice = rebate.getAmount() * ratesProvider.discountFactor(rebate.getCurrency(), paymentDate) /
142:             Math.abs(underlyingFx.getBaseCurrencyPayment().getAmount());
143:         return rebate.getCurrency().equals(ccyCounter) ? rebatePrice : todayFx * rebatePrice;
144:       }
145:       return 0d;
146:     }
