148:     DiscountFactors counterDiscountFactors = ratesProvider.discountFactors(ccyCounter);
149:     double rateBase = baseDiscountFactors.zeroRate(underlyingFx.getPaymentDate());
150:     double rateCounter = counterDiscountFactors.zeroRate(underlyingFx.getPaymentDate());
151:     double costOfCarry = rateCounter - rateBase;
152:     double dfBase = baseDiscountFactors.discountFactor(underlyingFx.getPaymentDate());
153:     double dfCounter = counterDiscountFactors.discountFactor(underlyingFx.getPaymentDate());
154:     double strike = underlyingOption.getStrike();
155:     double forward = todayFx * dfBase / dfCounter;
156:     double volatility = volatilities.volatility(currencyPair, underlyingOption.getExpiry(), strike, forward);
157:     double price = BARRIER_PRICER.price(
158:         todayFx, strike, timeToExpiry, costOfCarry, rateCounter, volatility, underlyingOption.getPutCall().isCall(), barrier);
159:     if (option.getRebate().isPresent()) {
160:       CurrencyAmount rebate = option.getRebate().get();
