545:     }
546:     FxRate forward = forwardFxRate(option, ratesProvider);
547:     CurrencyPair strikePair = option.getCurrencyPair();
548:     double strike = option.getUnderlyingOption().getStrike();
549:     return volatilities.volatility(strikePair, expiry, strike, forward.fxRate(strikePair));
550:   }
551: 
552:   //-------------------------------------------------------------------------
553:   /**
554:    * Calculates the currency exposure of the FX barrier option product.
555:    * 
556:    * @param option  the option product
557:    * @param ratesProvider  the rates provider
558:    * @param volatilities  the Black volatility provider
559:    * @return the currency exposure
560:    */
561:   public MultiCurrencyAmount currencyExposure(
562:       ResolvedFxSingleBarrierOption option,
563:       RatesProvider ratesProvider,
564:       BlackFxOptionVolatilities volatilities) {
565: 
566:     ResolvedFxVanillaOption underlyingOption = option.getUnderlyingOption();
567:     if (volatilities.relativeTime(underlyingOption.getExpiry()) < 0d) {
568:       return MultiCurrencyAmount.empty();
569:     }
570:     SimpleConstantContinuousBarrier barrier = (SimpleConstantContinuousBarrier) option.getBarrier();
571:     ResolvedFxSingle underlyingFx = underlyingOption.getUnderlying();
572:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
573:     double todayFx = ratesProvider.fxRate(currencyPair);
574:     if (alreadyTouched(todayFx, barrier)) {
575:       if (barrier.getKnockType().isKnockIn()) {
576:         return VANILLA_OPTION_PRICER.currencyExposure(underlyingOption, ratesProvider, volatilities);
577:       } else if (option.getRebate().isPresent()) {
578:         CurrencyAmount rebate = option.getRebate().get();
579:         DaysAdjustment spotLag = spotAdjustment(currencyPair);
580:         LocalDate paymentDate = spotLag.adjust(ratesProvider.getValuationDate(), ReferenceData.standard());
581:         double pv = (option.getUnderlyingOption().getLongShort().isLong() ? 1d : -1d) * rebate.getAmount() *
582:             ratesProvider.discountFactor(rebate.getCurrency(), paymentDate);
583:         Currency ccyCounter = underlyingFx.getCounterCurrencyPayment().getCurrency();
584:         double ceAmount = rebate.getCurrency().equals(ccyCounter) ? pv : todayFx * pv;
585:         return MultiCurrencyAmount.of(ccyCounter, ceAmount);
586:       }
587:       return MultiCurrencyAmount.empty();
588:     }
589:     ValueDerivatives priceDerivatives = priceDerivatives(option, ratesProvider, volatilities);
590:     double price = priceDerivatives.getValue();
591:     double delta = priceDerivatives.getDerivative(0);
592:     double signedNotional = signedNotional(underlyingOption);
593:     CurrencyAmount domestic = CurrencyAmount.of(currencyPair.getCounter(), (price - delta * todayFx) * signedNotional);
594:     CurrencyAmount foreign = CurrencyAmount.of(currencyPair.getBase(), delta * signedNotional);
595:     return MultiCurrencyAmount.of(domestic, foreign);
596:   }
597: 
598:   //-------------------------------------------------------------------------
599:   //  The derivatives are [0] spot, [1] strike, [2] rate, [3] cost-of-carry, [4] volatility, [5] timeToExpiry, [6] spot twice
600:   private ValueDerivatives priceDerivatives(
601:       ResolvedFxSingleBarrierOption option,
602:       RatesProvider ratesProvider,
603:       BlackFxOptionVolatilities volatilities) {
604: 
605:     validate(option, ratesProvider, volatilities);
606:     SimpleConstantContinuousBarrier barrier = (SimpleConstantContinuousBarrier) option.getBarrier();
607:     ResolvedFxVanillaOption underlyingOption = option.getUnderlyingOption();
608:     double[] derivatives = new double[7];
609:     if (volatilities.relativeTime(underlyingOption.getExpiry()) < 0d) {
610:       return ValueDerivatives.of(0d, DoubleArray.ofUnsafe(derivatives));
611:     }
612:     ResolvedFxSingle underlyingFx = underlyingOption.getUnderlying();
613:     CurrencyPair currencyPair = underlyingFx.getCurrencyPair();
614:     Currency ccyBase = currencyPair.getBase();
615:     Currency ccyCounter = currencyPair.getCounter();
616:     DiscountFactors baseDiscountFactors = ratesProvider.discountFactors(ccyBase);
617:     DiscountFactors counterDiscountFactors = ratesProvider.discountFactors(ccyCounter);
618: 
619:     double rateBase = baseDiscountFactors.zeroRate(underlyingFx.getPaymentDate());
620:     double rateCounter = counterDiscountFactors.zeroRate(underlyingFx.getPaymentDate());
621:     double costOfCarry = rateCounter - rateBase;
622:     double dfBase = baseDiscountFactors.discountFactor(underlyingFx.getPaymentDate());
623:     double dfCounter = counterDiscountFactors.discountFactor(underlyingFx.getPaymentDate());
624:     double todayFx = ratesProvider.fxRate(currencyPair);
625:     double strike = underlyingOption.getStrike();
626:     double forward = todayFx * dfBase / dfCounter;
627:     double volatility = volatilities.volatility(currencyPair, underlyingOption.getExpiry(), strike, forward);
628:     double timeToExpiry = volatilities.relativeTime(underlyingOption.getExpiry());
629:     ValueDerivatives valueDerivatives = BARRIER_PRICER.priceAdjoint(
630:         todayFx, strike, timeToExpiry, costOfCarry, rateCounter, volatility, underlyingOption.getPutCall().isCall(), barrier);
631:     if (!option.getRebate().isPresent()) {
632:       return valueDerivatives;
633:     }
634:     CurrencyAmount rebate = option.getRebate().get();
635:     ValueDerivatives valueDerivativesRebate = rebate.getCurrency().equals(ccyCounter) ?
636:         CASH_REBATE_PRICER.priceAdjoint(todayFx, timeToExpiry, costOfCarry, rateCounter, volatility, barrier.inverseKnockType()) :
637:         ASSET_REBATE_PRICER.priceAdjoint(todayFx, timeToExpiry, costOfCarry, rateCounter, volatility, barrier.inverseKnockType());
638:     double rebateRate = rebate.getAmount() / Math.abs(underlyingFx.getBaseCurrencyPayment().getAmount());
639:     double price = valueDerivatives.getValue() + rebateRate * valueDerivativesRebate.getValue();
640:     derivatives[0] = valueDerivatives.getDerivative(0) + rebateRate * valueDerivativesRebate.getDerivative(0);
641:     derivatives[1] = valueDerivatives.getDerivative(1);
642:     for (int i = 2; i < 7; ++i) {
643:       derivatives[i] = valueDerivatives.getDerivative(i) + rebateRate * valueDerivativesRebate.getDerivative(i - 1);
644:     }
645:     return ValueDerivatives.of(price, DoubleArray.ofUnsafe(derivatives));
646:   }
647: 
648:   //-------------------------------------------------------------------------
649:   // calculate spot lag for rebate
650:   private DaysAdjustment spotAdjustment(CurrencyPair currencyPair) {
651:     return FxIndex.extendedEnum().lookupAll().values().stream()
652:         .filter(index -> index.getCurrencyPair().equals(currencyPair))
653:         .findFirst()
654:         .map(FxIndex::getFixingDateOffset)
655:         .map(adjustment -> adjustment.toBuilder().days(-adjustment.getDays()).build())
656:         .orElseGet(() -> DaysAdjustment.ofBusinessDays(2, calendarForPair(currencyPair)));
657:   }
658: 
659:   private HolidayCalendarId calendarForPair(CurrencyPair pair) {
660:     return pair.toSet().stream()
661:         .map(currency -> defaultByCurrencyOrNoHolidays(currency))
662:         .reduce(HolidayCalendarIds.NO_HOLIDAYS, HolidayCalendarId::combinedWith);
663:   }
664: 
665:   private HolidayCalendarId defaultByCurrencyOrNoHolidays(Currency currency) {
666:     try {
667:       return HolidayCalendarId.defaultByCurrency(currency);
668:     } catch (IllegalArgumentException e) {
669:       return HolidayCalendarIds.NO_HOLIDAYS;
670:     }
671:   }
672: 
673:   //-------------------------------------------------------------------------
674:   private void validate(ResolvedFxSingleBarrierOption option,
675:       RatesProvider ratesProvider,
676:       BlackFxOptionVolatilities volatilities) {
677: 
678:     ArgChecker.isTrue(option.getBarrier() instanceof SimpleConstantContinuousBarrier,
679:         "Barrier should be SimpleConstantContinuousBarrier");
680:     ArgChecker.isTrue(ratesProvider.getValuationDate().isEqual(volatilities.getValuationDateTime().toLocalDate()),
681:         "Volatility and rate data must be for the same date");
682:   }
683: 
684:   // signed notional amount to computed present value and value Greeks
685:   private double signedNotional(ResolvedFxVanillaOption option) {
686:     return (option.getLongShort().isLong() ? 1d : -1d) *
687:         Math.abs(option.getUnderlying().getBaseCurrencyPayment().getAmount());
688:   }
689: 
690:   private boolean alreadyTouched(double fxRate, SimpleConstantContinuousBarrier barrier) {
691:     if (barrier.getBarrierType().isDown()) {
692:       return fxRate <= barrier.getBarrierLevel();
693:     }
694:     return fxRate >= barrier.getBarrierLevel();
695:   }
696: 
697: }
