35: /**
36:  * Handles the CSV files format for FX Single Barrier Option trades.
37:  */
38: public class FxSingleBarrierOptionTradeCsvPlugin implements TradeCsvParserPlugin, TradeCsvWriterPlugin<FxSingleBarrierOptionTrade> {
39: 
40:   /**
41:    * The singleton instance of the plugin.
42:    */
43:   public static final FxSingleBarrierOptionTradeCsvPlugin INSTANCE = new FxSingleBarrierOptionTradeCsvPlugin();
44: 
45:   /**
46:    * The CSV headers.
47:    */
48:   public static final Set<String> HEADERS = ImmutableSet.<String>builder()
49:       .addAll(FxVanillaOptionTradeCsvPlugin.INSTANCE.headers(ImmutableList.of()))
50:       .add(BARRIER_TYPE_FIELD)
51:       .add(KNOCK_TYPE_FIELD)
52:       .add(BARRIER_LEVEL_FIELD)
53:       .add(REBATE_AMOUNT_FIELD)
54:       .add(REBATE_CURRENCY_FIELD)
55:       .add(REBATE_DIRECTION_FIELD)
56:       .build();
57: 
58:   /**
59:    * Restricted constructor
60:    */
61:   private FxSingleBarrierOptionTradeCsvPlugin() {
62:   }
63: 
64:   @Override
65:   public Set<String> tradeTypeNames() {
66:     return ImmutableSet.of("FXSINGLEBARRIEROPTION", "FX SINGLE BARRIER OPTION");
67:   }
68: 
69:   @Override
70:   public Optional<Trade> parseTrade(
71:       Class<?> requiredJavaType,
72:       CsvRow baseRow,
73:       List<CsvRow> additionalRows,
74:       TradeInfo info,
75:       TradeCsvInfoResolver resolver) {
76: 
77:     if (requiredJavaType.isAssignableFrom(FxSingleBarrierOptionTrade.class)) {
78:       return Optional.of(parse(baseRow, info, resolver));
79:     }
80:     return Optional.empty();
81:   }
82: 
83:   private FxSingleBarrierOptionTrade parse(CsvRow row, TradeInfo info, TradeCsvInfoResolver resolver) {
84:     FxVanillaOptionTrade vanillaOptionTrade = resolver.parseFxVanillaOptionTrade(row, info);
85:     Barrier barrier = CsvLoaderUtils.parseBarrierFromDefaultFields(row);
86: 
87:     FxSingleBarrierOption.Builder productBuilder = FxSingleBarrierOption.builder()
88:         .underlyingOption(vanillaOptionTrade.getProduct())
89:         .barrier(barrier);
90: 
91:     CsvLoaderUtils.tryParseCurrencyAmountWithDirection(
92:         row,
93:         REBATE_CURRENCY_FIELD,
94:         REBATE_AMOUNT_FIELD,
95:         REBATE_DIRECTION_FIELD
96:     ).ifPresent(productBuilder::rebate);
97: 
98:     FxVanillaOption option = vanillaOptionTrade.getProduct();
99:     return FxSingleBarrierOptionTrade.builder()
100:         .product(productBuilder.build())
101:         .premium(CsvLoaderUtils.tryParsePremiumFromDefaultFields(row)
102:             .orElse(AdjustablePayment.of(option.getCurrencyPair().getBase(), 0d, option.getExpiryDate())))
103:         .info(info)
104:         .build();
105:   }
106: 
107:   @Override
108:   public String getName() {
109:     return FxSingleBarrierOptionTrade.class.getSimpleName();
110:   }
111: 
112:   @Override
113:   public Set<Class<?>> supportedTradeTypes() {
114:     return ImmutableSet.of(FxSingleBarrierOptionTrade.class);
115:   }
116: 
117:   @Override
118:   public Set<String> headers(List<FxSingleBarrierOptionTrade> trades) {
119:     return HEADERS;
120:   }
121: 
122:   @Override
123:   public void writeCsv(CsvOutput.CsvRowOutputWithHeaders csv, FxSingleBarrierOptionTrade trade) {
124:     csv.writeCell(TRADE_TYPE_FIELD, "FxSingleBarrierOption");
125:     writeSingleBarrierOption(csv, trade.getProduct());
126:     CsvWriterUtils.writePremiumFields(csv, trade.getPremium());
127:     csv.writeNewLine();
128:   }
129: 
130:   void writeSingleBarrierOption(CsvOutput.CsvRowOutputWithHeaders csv, FxSingleBarrierOption product) {
131:     CsvWriterUtils.writeFxVanillaOption(csv, product.getUnderlyingOption());
132:     CsvWriterUtils.writeBarrier(csv, product.getBarrier(), LocalDate.now(ZoneId.systemDefault()));
133:     product.getRebate().ifPresent(ccyAmount -> CsvWriterUtils.writeCurrencyAmount(
134:         csv,
135:         ccyAmount,
136:         REBATE_AMOUNT_FIELD,
137:         REBATE_CURRENCY_FIELD,
138:         REBATE_DIRECTION_FIELD));
139:   }
140: }
